const prob = (typeof msg.run_probability === 'number') ? msg.run_probability : 0.60;
const roll = Math.random();

const target = msg.target_entity || 'light.main_floor';

const minB = Number.isFinite(msg.min_brightness) ? msg.min_brightness : 20;
const maxB = Number.isFinite(msg.max_brightness) ? msg.max_brightness : 70;
const minM = Number.isFinite(msg.min_minutes_on) ? msg.min_minutes_on : 8;
const maxM = Number.isFinite(msg.max_minutes_on) ? msg.max_minutes_on : 40;

const randInt = (a,b) => Math.floor(a + Math.random() * (b - a + 1));

if (roll > prob) {
  msg.simulation = { skipped: true, reason: `probability gate: roll=${roll.toFixed(2)} > prob=${prob}` };
  return [null, msg];
}

const brightness = randInt(minB, maxB);
const minutesOn = randInt(minM, maxM);

msg.simulation = {
  skipped: false,
  target,
  brightness_pct: brightness,
  minutes_on: minutesOn,
  transition_on_s: 2,
  transition_off_s: 2
};

return [msg, null];

// Fridge Cycle Classifier (Adaptive)
// Input: msg.payload = current power (W)
// Outputs: msg.event in ["idle","run_start","running","compressor_cycle","low_power"]

const FRIENDLY_NAME = env.get("FRIENDLY_NAME") || "Appliance";

const raw = msg.payload;
const p = Number(raw);
const now = Date.now();

// Handle HA "unknown"/"unavailable"
if (!Number.isFinite(p)) {
  // Cache last power as 0 or leave unchanged—choose one. I prefer unchanged.
  msg.event = "low_power";
  msg.gf = { watts: null, state: "unknown" };
  return msg;
}

// ✅ Cache latest power for alert builder
flow.set(`${FRIENDLY_NAME}_last_power`, p);

// Tuning knobs
const OUTAGE_W = 15;          // below this likely unplugged / breaker / outage
const MIN_RUN_MS = 90 * 1000;   // must run at least 90s to count as a real compressor run
const MIN_OFF_MS = 60 * 1000;   // must be idle at least 60s before allowing a new run

// ✅ Make learned stats per appliance (prevents garage/wine cross-contamination)
const STATS_KEY = `${FRIENDLY_NAME}_fridge_stats`;

let st = flow.get(STATS_KEY) || {
  idleAvg: 3,
  runAvg: 120,
  state: "idle",   // "idle" or "running"
  runStart: 0,
  lastRunEnd: 0,
  lastCycleTs: 0
};

function ema(oldVal, newVal, alpha) {
  return oldVal + alpha * (newVal - oldVal);
}

const startTh = Math.max(st.idleAvg + 25, (st.idleAvg * 2) + 10);
const endTh = Math.max(st.idleAvg + 10, (st.idleAvg * 1.6) + 6);

let event = "idle";

if (p < OUTAGE_W) {
  event = "low_power";
} else if (st.state === "idle") {
  st.idleAvg = ema(st.idleAvg, p, 0.02);

  const enoughOff = (now - st.lastRunEnd) > MIN_OFF_MS;
  if (enoughOff && p > startTh) {
    st.state = "running";
    st.runStart = now;
    event = "run_start";
  } else {
    event = "idle";
  }
} else if (st.state === "running") {
  if (p > startTh) st.runAvg = ema(st.runAvg, p, 0.02);

  const runningLongEnough = (now - st.runStart) >= MIN_RUN_MS;

  if (p < endTh) {
    st.state = "idle";
    st.lastRunEnd = now;

    if (runningLongEnough) {
      st.lastCycleTs = now;
      event = "run_end";
    } else {
      event = "idle";
    }
  } else {
    event = "running";
  }
}

// ✅ Persist learned stats per appliance
flow.set(STATS_KEY, st);

msg.gf = {
  appliance: FRIENDLY_NAME,
  watts: p,
  idleAvg: Number(st.idleAvg.toFixed(1)),
  runAvg: Number(st.runAvg.toFixed(0)),
  startTh: Number(startTh.toFixed(1)),
  endTh: Number(endTh.toFixed(1)),
  state: st.state
};

// Emit a cycle marker when we get a true cycle end
if (event === "run_end") {
  msg.event = "compressor_cycle";

  // ✅ Cache last cycle timestamp for alert builder
  flow.set(`${FRIENDLY_NAME}_last_cycle_ts`, now);
} else {
  msg.event = event;
}

return msg;

// Build Alert + Cooldown (Subflow-safe)

const type = String(msg.payload || '');   // e.g. "OUTAGE_DETECTED" or "NO_CYCLE_2H"
const COOLDOWN_MS = 2 * 60 * 60 * 1000;   // 2 hours
const now = Date.now();

// ✅ Subflow env var (string)
const FRIENDLY_NAME = env.get("FRIENDLY_NAME") || "Appliance";

// Cooldown key is per appliance + per alert type
const key = `${FRIENDLY_NAME}_last_alert_${type}`;
const last = Number(flow.get(key) || 0);
if (now - last < COOLDOWN_MS) return null;
flow.set(key, now);

// Pull latest cached telemetry (your other nodes should set these)
const watts     = Number(flow.get(`${FRIENDLY_NAME}_last_power`) || 0);
const lastCycle = Number(flow.get(`${FRIENDLY_NAME}_last_cycle_ts`) || 0);

let title = `${FRIENDLY_NAME} Alert`;
let text  = '';

if (type === 'OUTAGE_DETECTED') {
  title = `${FRIENDLY_NAME} power loss suspected`;
  text  = `${FRIENDLY_NAME} plug has been <15W for 45 minutes. Current power: ${watts.toFixed(1)}W.`;
} else if (type === 'NO_CYCLE_2H') {
  title = `${FRIENDLY_NAME} not cycling`;
  const mins = lastCycle ? Math.round((now - lastCycle) / 60000) : 'unknown';
  text  = `${FRIENDLY_NAME}: no compressor cycle detected for ~${mins} minutes. Current power: ${watts.toFixed(1)}W.`;
} else {
  title = `${FRIENDLY_NAME} alert`;
  text  = `${FRIENDLY_NAME}: unknown alert type: ${type}`;
}

msg.alert = {
  appliance: FRIENDLY_NAME,
  type,
  title,
  text,
  watts,
  ts: new Date(now).toISOString()
};

msg.payload = text;
return msg;

const mode  = String(global.get("jarvis_mode") || "unknown").toLowerCase();
const quiet = global.get("quiet_hours") === "on";

let allowTTS = true;
if (quiet) allowTTS = false;
if (mode.includes("vacation")) allowTTS = false;

msg.allow_tts = allowTTS;
return msg;

const vac = (msg.vacation_mode || '').toLowerCase() === 'on';
const bypass = msg.vacation_bypass === true;

msg._vacation_blocked = vac && !bypass;

// Route using switch node downstream
return msg;

msg.door_name = env.get('DOOR_NAME') || 'Door';
msg.mode_lookup = env.get('MODE_ENTITY') || 'input_select.jarvis_mode';
