    }];
}

const model = msg.model || env.get('DEFAULT_MODEL') || 'gpt-5-mini';
const system = (typeof msg.system === 'string' && msg.system.trim())
    ? msg.system.trim()
    : 'You are a concise smart-home analyst. Be practical and avoid speculation.';

msg.method = 'POST';
msg.url = env.get('OPENAI_URL');
