                }
            ]
        },
        {
            role: 'user',
            content: [
                {
                    type: 'input_text',
                    text: prompt
                }
            ]
        }
    ]
};

msg.ai_request = {
    provider: 'openai',
    model,
    prompt,
    system,
    started_at: new Date().toISOString()
