return [msg, null];

const raw = msg.payload || {};
let text = '';

if (Array.isArray(raw.output)) {
    for (const item of raw.output) {
        if (Array.isArray(item.content)) {
            for (const c of item.content) {
                if (c.type === 'output_text' && c.text) {
                    text += c.text;
                }
            }
        }
    }
}

if (!text && typeof raw.output_text === 'string') {
    text = raw.output_text;
}

if (!text) {
    msg.payload = `No output_text found in OpenAI response: ${JSON.stringify(raw)}`;
    msg.error = true;
    return [null, msg];
}

msg.raw_openai = raw;
msg.payload = text;
msg.ai_result = {
    provider: 'openai',
    model: raw.model || msg.ai_request?.model,
    response_id: raw.id,
    completed_at: new Date().toISOString()
};

return [msg, null];

let detail = 'Unknown OpenAI error';
const raw = msg.payload;

if (msg.statusCode && (msg.statusCode < 200 || msg.statusCode > 299)) {
    detail = `HTTP ${msg.statusCode}`;
    if (raw && raw.error) {
        if (typeof raw.error === 'string') {
            detail += `: ${raw.error}`;
        } else if (raw.error.message) {
            detail += `: ${raw.error.message}`;
        } else {
            detail += `: ${JSON.stringify(raw.error)}`;
        }
    } else if (typeof raw === 'string') {
        detail += `: ${raw}`;
    } else if (raw) {
        detail += `: ${JSON.stringify(raw)}`;
    }
} else if (typeof raw === 'string') {
    detail = raw;
} else if (raw && typeof raw === 'object') {
    if (raw.error) {
        if (typeof raw.error === 'string') {
            detail = raw.error;
        } else if (raw.error.message) {
            detail = raw.error.message;
        } else {
            detail = JSON.stringify(raw.error);
        }
    } else {
        detail = JSON.stringify(raw);
    }
}

msg.error = true;
msg.payload = detail;
msg.raw_openai = raw;
msg.ai_result = {
    provider: 'openai',
    failed_at: new Date().toISOString()
};

return [msg];

