let w = null;
const p = msg.payload;

if (typeof p === 'number') {
    w = p;
} else if (typeof p === 'string') {
    const n = Number(p);
    if (!Number.isNaN(n)) w = n;
} else if (p && typeof p === 'object') {
    const candidates = [
        p.total_w,
        p.total_power,
        p.power,
        p.apower,
        p.active_power,
        p.payload,
        p.result && p.result.total_w,
        p.result && p.result.total_power,
        p.data && p.data.total_w,
        p.data && p.data.total_power
    ];
    for (const c of candidates) {
        const n = Number(c);
        if (!Number.isNaN(n)) {
            w = n;
            break;
        }
    }
}

if (w === null) return null;
msg.payload = Math.round(w);
msg.total_w = msg.payload;
return msg;

let st = flow.get('appliance_detector_v2') || {
    training: { active: false, name: null, startTs: 0, startBaseline: 0, events: [] },
    signatures: {},
    candidates: {},
    active: {},
    history: []
};

const p = msg.payload || {};
const cmd = String(p.cmd || '').toLowerCase();
const now = Date.now();
let out = null;

if (cmd === 'start') {
    const name = String(p.name || '').trim().toLowerCase().replace(/\s+/g, '_');
    if (!name) return null;
    st.training = {
        active: true,
        name,
        startTs: now,
        startBaseline: Number(flow.get('appliance_detector_v2_last_total_w') || 0),
        events: []
    };
    out = {
        topic: 'shelly/main_panel/detector/state',
        payload: {
            training: st.training,
            msg: `training started for ${name}`,
            ts: new Date(now).toISOString()
        }
    };
} else if (cmd === 'stop') {
    if (!st.training.active) return null;
    const t = st.training;
    const deltasOn = t.events.filter(e => e.type === 'on').map(e => Math.abs(e.delta_w));
    const deltasOff = t.events.filter(e => e.type === 'off').map(e => Math.abs(e.delta_w));
    const runtimes = t.events.filter(e => e.type === 'off' && typeof e.runtime_s === 'number').map(e => e.runtime_s);

    function avg(arr) {
        if (!arr.length) return 0;
        return arr.reduce((a,b)=>a+b,0)/arr.length;
    }
    function spread(arr) {
        if (!arr.length) return 0;
        const mn = Math.min(...arr);
        const mx = Math.max(...arr);
        return mx - mn;
    }

    const nominal = Math.round(avg(deltasOn.length ? deltasOn : deltasOff));
    const tol = Math.max(150, Math.round((spread(deltasOn.length ? deltasOn : deltasOff) * 0.6) || nominal * 0.2 || 250));
    const minOnMs = runtimes.length ? Math.max(5000, Math.round(Math.min(...runtimes) * 1000 * 0.7)) : 10000;
    const maxOnMs = runtimes.length ? Math.max(60000, Math.round(Math.max(...runtimes) * 1000 * 1.5)) : 3600000;

    st.signatures[t.name] = {
        name: t.name,
        nominal,
        tol,
        minOnMs,
        maxOnMs,
        learned: true,
        samples_on: deltasOn.length,
        samples_off: deltasOff.length,
        updated: new Date(now).toISOString()
    };

    st.training = { active: false, name: null, startTs: 0, startBaseline: 0, events: [] };
    out = {
        topic: 'shelly/main_panel/detector/state',
        payload: {
            msg: 'training stopped and signature saved',
            saved_signature: st.signatures[t.name],
            ts: new Date(now).toISOString()
        }
    };
} else if (cmd === 'list') {
    out = {
        topic: 'shelly/main_panel/detector/state',
        payload: {
            training: st.training,
            signatures: st.signatures,
            candidates: st.candidates,
            ts: new Date(now).toISOString()
        }
    };
} else if (cmd === 'clear_candidates') {
    st.candidates = {};
    out = {
        topic: 'shelly/main_panel/detector/state',
        payload: {
            msg: 'candidates cleared',
            ts: new Date(now).toISOString()
        }
    };
} else if (cmd === 'clear_signatures') {
    st.signatures = {};
    out = {
        topic: 'shelly/main_panel/detector/state',
        payload: {
            msg: 'signatures cleared',
            ts: new Date(now).toISOString()
        }
    };
} else {
    return null;
}

flow.set('appliance_detector_v2', st);
return out;

// V2 whole-home step detector with learnable signatures.
// Input: msg.payload = total watts
// Output 1: known appliance event
// Output 2: unknown candidate event
// Output 3: diagnostics/state

const now = Date.now();
const totalW = Number(msg.payload);
if (Number.isNaN(totalW)) return null;
flow.set('appliance_detector_v2_last_total_w', totalW);

const DEFAULT_SIGNATURES = {
    kettle:        { name: 'kettle',        nominal: 1500, tol: 450, minOnMs: 10000,  maxOnMs: 10 * 60 * 1000, learned: false },
    microwave:     { name: 'microwave',     nominal: 1300, tol: 450, minOnMs: 10000,  maxOnMs: 20 * 60 * 1000, learned: false },
    toaster:       { name: 'toaster',       nominal: 1200, tol: 400, minOnMs: 8000,   maxOnMs: 10 * 60 * 1000, learned: false },
    coffee_maker:  { name: 'coffee_maker',  nominal: 900,  tol: 300, minOnMs: 30000,  maxOnMs: 30 * 60 * 1000, learned: false },
    space_heater:  { name: 'space_heater',  nominal: 1500, tol: 450, minOnMs: 30000,  maxOnMs: 12 * 60 * 60 * 1000, learned: false },
    oven_element:  { name: 'oven_element',  nominal: 2400, tol: 700, minOnMs: 30000,  maxOnMs: 3 * 60 * 60 * 1000, learned: false },
    dryer_element: { name: 'dryer_element', nominal: 5000, tol: 1500,minOnMs: 30000,  maxOnMs: 3 * 60 * 60 * 1000, learned: false },
    water_heater:  { name: 'water_heater',  nominal: 4500, tol: 1200,minOnMs: 60000,  maxOnMs: 3 * 60 * 60 * 1000, learned: false }
};

const MIN_STEP_W = 250;
const REFRACTORY_MS = 7000;
const OFF_TOL_EXTRA = 175;
const MAX_HISTORY = 100;
const MAX_CANDIDATES = 30;

let st = flow.get('appliance_detector_v2') || {
    prevW: totalW,
    lastStepTs: 0,
    training: { active: false, name: null, startTs: 0, startBaseline: 0, events: [] },
    signatures: {},
    candidates: {},
    active: {},
    history: []
};

// merge defaults without overwriting learned/custom signatures
for (const [k, v] of Object.entries(DEFAULT_SIGNATURES)) {
    if (!st.signatures[k]) st.signatures[k] = v;
}

const delta = totalW - Number(st.prevW || 0);
st.prevW = totalW;

function confidenceFromScore(scoreRatio, learned) {
    if (scoreRatio <= 0.12) return learned ? 'high' : 'medium';
    if (scoreRatio <= 0.25) return 'medium';
    return 'low';
}

function bestOnMatch(stepW) {
    let best = null;
    let bestScore = Infinity;
    for (const sig of Object.values(st.signatures)) {
        if (st.active[sig.name]) continue;
        const score = Math.abs(stepW - sig.nominal);
        if (score <= sig.tol && score < bestScore) {
            best = sig;
            bestScore = score;
        }
    }
    if (!best) return null;
    return { sig: best, score: bestScore, ratio: best.nominal ? bestScore / best.nominal : 1 };
}

function bestOffMatch(stepAbs) {
    let best = null;
    let bestScore = Infinity;
    for (const [name, a] of Object.entries(st.active)) {
        const sig = st.signatures[name];
        if (!sig) continue;
        const runtime = now - a.startedAt;
        if (runtime < sig.minOnMs) continue;
        const score = Math.abs(stepAbs - a.stepW);
        if (score <= (sig.tol + OFF_TOL_EXTRA) && score < bestScore) {
            best = { sig, active: a, score, ratio: a.stepW ? score / a.stepW : 1 };
            bestScore = score;
        }
    }
    return best;
}

function registerCandidate(type, stepW, totalW) {
    const band = Math.round(stepW / 50) * 50;
    const key = `${type}_${band}`;
    let c = st.candidates[key] || {
        key,
        type,
        nominal_band_w: band,
        hits: 0,
        last_seen: null,
        examples: []
    };
    c.hits += 1;
    c.last_seen = new Date(now).toISOString();
    c.examples.push({ ts: c.last_seen, step_w: Math.round(stepW), total_w: totalW });
    c.examples = c.examples.slice(-5);
    st.candidates[key] = c;

    const keys = Object.keys(st.candidates);
    if (keys.length > MAX_CANDIDATES) {
        keys.sort((a,b) => new Date(st.candidates[a].last_seen) - new Date(st.candidates[b].last_seen));
        delete st.candidates[keys[0]];
    }
    return c;
}

// prune stale actives
for (const [name, a] of Object.entries(st.active)) {
    const sig = st.signatures[name];
    if (!sig) {
        delete st.active[name];
        continue;
    }
    if ((now - a.startedAt) > sig.maxOnMs) {
        delete st.active[name];
    }
}

let knownEvent = null;
let unknownEvent = null;
let diag = null;

if (Math.abs(delta) >= MIN_STEP_W && (now - st.lastStepTs) >= REFRACTORY_MS) {
    st.lastStepTs = now;

    if (delta > 0) {
        const m = bestOnMatch(delta);
        if (m) {
            st.active[m.sig.name] = {
                name: m.sig.name,
                stepW: Math.round(delta),
                startedAt: now,
                totalAtStart: totalW
            };
            knownEvent = {
                topic: 'shelly/main_panel/detector/event',
                payload: {
                    appliance: m.sig.name,
                    state: 'on',
                    step_w: Math.round(delta),
                    total_w: totalW,
                    confidence: confidenceFromScore(m.ratio, !!m.sig.learned),
                    learned_signature: !!m.sig.learned,
                    ts: new Date(now).toISOString()
                }
            };
        } else {
            const c = registerCandidate('on', Math.abs(delta), totalW);
            unknownEvent = {
                topic: 'shelly/main_panel/detector/unknown',
                payload: {
                    state: 'on',
                    step_w: Math.round(delta),
                    total_w: totalW,
                    candidate_key: c.key,
                    hits: c.hits,
                    ts: c.last_seen
                }
            };
        }
    } else {
        const m = bestOffMatch(Math.abs(delta));
        if (m) {
            const runtimeMs = now - m.active.startedAt;
            delete st.active[m.sig.name];
            knownEvent = {
                topic: 'shelly/main_panel/detector/event',
                payload: {
                    appliance: m.sig.name,
                    state: 'off',
                    step_w: Math.round(delta),
                    total_w: totalW,
                    runtime_s: Math.round(runtimeMs / 1000),
                    confidence: confidenceFromScore(m.ratio, !!m.sig.learned),
                    learned_signature: !!m.sig.learned,
                    ts: new Date(now).toISOString()
                }
            };

            if (st.training.active) {
                st.training.events.push({
                    type: 'off',
                    appliance: m.sig.name,
                    delta_w: Math.round(delta),
                    total_w: totalW,
                    runtime_s: Math.round(runtimeMs / 1000),
                    ts: new Date(now).toISOString()
                });
            }
        } else {
            const c = registerCandidate('off', Math.abs(delta), totalW);
            unknownEvent = {
                topic: 'shelly/main_panel/detector/unknown',
                payload: {
                    state: 'off',
                    step_w: Math.round(delta),
                    total_w: totalW,
                    candidate_key: c.key,
                    hits: c.hits,
                    ts: c.last_seen
                }
            };
        }
    }
}

if (knownEvent && st.training.active) {
    st.training.events.push({
        type: knownEvent.payload.state,
        appliance: knownEvent.payload.appliance,
        delta_w: knownEvent.payload.step_w,
        total_w: knownEvent.payload.total_w,
        runtime_s: knownEvent.payload.runtime_s,
        ts: knownEvent.payload.ts
    });
}

st.history.push({
    ts: new Date(now).toISOString(),
    total_w: totalW,
    delta_w: Math.round(delta),
    event: knownEvent ? knownEvent.payload : null,
    unknown: unknownEvent ? unknownEvent.payload : null
});
st.history = st.history.slice(-MAX_HISTORY);

diag = {
    topic: 'shelly/main_panel/detector/diagnostics',
    payload: {
        ts: new Date(now).toISOString(),
        total_w: totalW,
        delta_w: Math.round(delta),
        active_appliances: Object.keys(st.active),
        training: st.training,
        signatures_count: Object.keys(st.signatures).length,
        candidates_count: Object.keys(st.candidates).length
    }
};

flow.set('appliance_detector_v2', st);
return [knownEvent, unknownEvent, diag];

flow.set('shelly_main_panel_power', {
    a_w: 0,
    c_w: 0,
    last_a_ts: 0,
    last_c_ts: 0
});
node.status({fill:'green',shape:'dot',text:'cache reset'});
return null;

// Normalizes Shelly Pro 3EM MQTT status messages into one topic:
//   shelly/main_panel/total_w
//
// Assumptions for split-phase install:
//   Phase A = em:0
//   Phase C = em:2
//   Phase B unused
//
// Expected input topics examples:
//   shelly/main_panel/status/em:0
//   shelly/main_panel/status/em:2
//
// Expected payload examples may include one of:
//   {"apower":230.1}
//   {"act_power":230.1}
//   {"active_power":230.1}
//   {"power":230.1}
//   {"a_act_power":230.1}  // not expected but tolerated

const topic = String(msg.topic || '');
const p = msg.payload || {};

function getPower(obj) {
    const candidates = [
        obj.apower,
        obj.act_power,
        obj.active_power,
        obj.power,
        obj.a_act_power,
        obj.data && obj.data.apower,
        obj.data && obj.data.act_power,
        obj.data && obj.data.active_power,
        obj.result && obj.result.apower,
        obj.result && obj.result.act_power,
        obj.result && obj.result.active_power
    ];
    for (const c of candidates) {
        const n = Number(c);
        if (!Number.isNaN(n)) return n;
    }
    return null;
}

const watts = getPower(p);
if (watts === null) return null;

let st = flow.get('shelly_main_panel_power') || {
    a_w: 0,
    c_w: 0,
    last_a_ts: 0,
    last_c_ts: 0
};

const now = Date.now();

if (topic.endsWith('/em:0')) {
    st.a_w = watts;
    st.last_a_ts = now;
} else if (topic.endsWith('/em:2')) {
    st.c_w = watts;
    st.last_c_ts = now;
} else {
    return null;
}

flow.set('shelly_main_panel_power', st);

const total = Math.round((Number(st.a_w) || 0) + (Number(st.c_w) || 0));

const out1 = {
    topic: 'shelly/main_panel/total_w',
    payload: total
};

const out2 = {
    topic: 'shelly/main_panel/diagnostics/power_state',
    payload: {
        phase_a_w: Math.round(Number(st.a_w) || 0),
        phase_c_w: Math.round(Number(st.c_w) || 0),
        total_w: total,
        last_a_ts: st.last_a_ts,
        last_c_ts: st.last_c_ts,
        iso_ts: new Date(now).toISOString()
    }
};

return [out1, out2];

msg.system = "You are a smart-home lighting troubleshooting assistant. Use only the information provided. Be concise, practical, and avoid speculation. Return 3 short bullet points followed by one short likely-cause line.";
msg.model = "gpt-5-mini";

const room = msg.room_name || "Unknown room";
const motion = msg.motion ?? "unknown";
const lux = msg.lux ?? "unknown";
const luxThreshold = msg.lux_threshold ?? "unknown";
const jarvisMode = msg.jarvis_mode ?? "unknown";
const quietHours = msg.quiet_hours ?? "unknown";
const readingMode = msg.reading_mode ?? "unknown";
const roomActive = msg.room_active ?? "unknown";

msg.payload = `Lighting diagnostic:\n\nRoom: ${room}\nMotion sensor: ${motion}\nAmbient lux: ${lux}\nLux threshold: ${luxThreshold}\nJarvis mode: ${jarvisMode}\nQuiet hours: ${quietHours}\nReading mode: ${readingMode}\nRoom active: ${roomActive}\n\nExplain why the light may not have turned on.`;

return msg;

const asBool = (v) => {
    if (typeof v === 'boolean') return v;
    const s = (v ?? '').toString().trim().toLowerCase();
    return ['true', 'on', 'yes', '1'].includes(s);
};

const asStr = (v, fallback = '') => (v ?? fallback).toString().trim();

// Inputs
const internet_up = asBool(msg.internet_up);
const manual_red = asBool(msg.manual_red);
const quiet_hours = asBool(msg.quiet_hours);
const house_mode = asStr(msg.house_mode, 'home').toLowerCase();

// Outputs
let target_posture = 'Home';
let posture_reason = '';
let security_condition = 'Green';

// Priority 1: hard manual override
if (manual_red) {
    target_posture = 'Alert';
    security_condition = 'Red';
    posture_reason = 'manual_red=true -> Alert';
}

// Priority 2: explicit house modes
else if (house_mode.includes('vacation')) {
    target_posture = 'Vacation';
    security_condition = internet_up ? 'Green' : 'Amber';
    posture_reason = internet_up
        ? 'house_mode=vacation -> Vacation'
        : 'house_mode=vacation + internet down -> Vacation (degraded)';
}
else if (house_mode.includes('away')) {
    target_posture = 'Away';
    security_condition = internet_up ? 'Green' : 'Amber';
    posture_reason = internet_up
        ? 'house_mode=away -> Away'
        : 'house_mode=away + internet down -> Away (degraded)';
}
else if (house_mode.includes('night') || house_mode.includes('sleep')) {
    target_posture = 'Night';
    security_condition = internet_up ? 'Green' : 'Amber';
    posture_reason = internet_up
        ? 'house_mode=night -> Night'
        : 'house_mode=night + internet down -> Night (degraded)';
}

// Priority 3: occupied states
else {
    // You can reserve Evening for either:
    // a) explicit evening house_mode
    // b) quiet_hours=true while still occupied
    if (house_mode.includes('evening')) {
        target_posture = 'Evening';
        security_condition = internet_up ? 'Green' : 'Amber';
        posture_reason = internet_up
            ? 'house_mode=evening -> Evening'
            : 'house_mode=evening + internet down -> Evening (degraded)';
    } else if (quiet_hours) {
        // occupied, winding down, but not necessarily night mode yet
        target_posture = 'Evening';
        security_condition = internet_up ? 'Green' : 'Amber';
        posture_reason = internet_up
            ? 'quiet_hours=true -> Evening'
            : 'quiet_hours=true + internet down -> Evening (degraded)';
    } else {
        target_posture = 'Home';
        security_condition = internet_up ? 'Green' : 'Amber';
        posture_reason = internet_up
            ? 'default occupied state -> Home'
            : 'default occupied state + internet down -> Home (degraded)';
    }
}

// Final guardrail for HA input_select.security_posture
const allowed_postures = ['Home', 'Evening', 'Night', 'Away', 'Vacation', 'Alert'];
if (!allowed_postures.includes(target_posture)) {
    posture_reason = `invalid target_posture (${target_posture}) -> forcing Home. prev_reason=${posture_reason}`;
    target_posture = 'Home';
}

// Write outputs
msg.target_posture = target_posture;
msg.posture_reason = posture_reason;
msg.security_condition = security_condition;

msg.payload = {
    target_posture,
    posture_reason,
    security_condition,
    inputs: {
        internet_up,
        manual_red,
        quiet_hours,
        house_mode
    }
};

return msg;

const toBool = (v) => {
    if (typeof v === 'boolean') return v;
    const s = (v ?? '').toString().trim().toLowerCase();
    return s === 'true' || s === 'on' || s === 'yes' || s === 'home';
};

msg.house_mode = (msg.house_mode ?? '').toString().trim().toLowerCase();
msg.security_posture = (msg.security_posture ?? '').toString().trim().toLowerCase();
msg.internet_up = toBool(msg.internet_up);
msg.manual_red = toBool(msg.manual_red);
msg.quiet_hours = toBool(msg.quiet_hours);

return msg;

const p = (msg.target_posture || msg.security || msg.payload || '').toString().trim().toLowerCase();

let haPosture = 'Home';

switch (p) {
