  return null;
}

// Stores latest mode/lux in flow context and computes a baseline brightness_pct.
// Hysteresis prevents oscillation around thresholds.

const topic = msg.topic;

if (topic === 'jarvis_mode') {
  flow.set('stair_mode', String(msg.payload || 'unknown').toLowerCase());
}
if (topic === 'lux') {
  const lux = Number(msg.payload);
  if (!Number.isFinite(lux)) return null;
  flow.set('stair_lux', lux);
}

const mode = flow.get('stair_mode') || 'unknown';
const lux  = Number(flow.get('stair_lux'));
if (!Number.isFinite(lux)) return null;

// --- Tunables ---
const TH_DARK = 10;   // <10 lux
const TH_DIM  = 30;   // 10-30 lux
const HYS     = 3;    // hysteresis band (+/-)

// Maintain a lux band state with hysteresis: 'dark' | 'dim' | 'bright'
let band = flow.get('stair_lux_band') || 'dim';

if (band === 'dark') {
  if (lux > (TH_DARK + HYS)) band = 'dim';
} else if (band === 'dim') {
  if (lux < (TH_DARK - HYS)) band = 'dark';
  else if (lux > (TH_DIM + HYS)) band = 'bright';
} else if (band === 'bright') {
  if (lux < (TH_DIM - HYS)) band = 'dim';
}
flow.set('stair_lux_band', band);

// Determine baseline by mode + band
const isMorningDay = mode.includes('morning') || mode.includes('day');
const isEvening    = mode.includes('evening');
const isNight      = mode.includes('night') || mode.includes('sleep');
const isAway       = mode.includes('away');
const isVacation   = mode.includes('vacation');

let target = 0;
let reason = '';

if (isMorningDay) {
  if (band === 'dark') { target = 2; reason = `mode=${mode}, band=${band} => 2% safety marker`; }
  else { target = 0; reason = `mode=${mode}, band=${band} => OFF`; }
}
else if (isEvening) {
  // Evening: gentle marker if it’s actually dark.
  if (band === 'dark') { target = 6; reason = `mode=${mode}, band=${band} => 6%`; }
  else if (band === 'dim') { target = 3; reason = `mode=${mode}, band=${band} => 3%`; }
  else { target = 0; reason = `mode=${mode}, band=${band} => OFF`; }
}
else if (isNight || isAway || isVacation) {
  // Night: locator only. Bump provides the real light.
  if (band === 'dark') { target = 2; reason = `mode=${mode}, band=${band} => 2% locator`; }
  else if (band === 'dim') { target = 1; reason = `mode=${mode}, band=${band} => 1% locator`; }
  else { target = 0; reason = `mode=${mode}, band=${band} => OFF`; }
}
else {
  // Unknown: conservative but not bright
  if (band === 'dark') { target = 2; reason = `mode=${mode}, band=${band} => 2% (unknown mode)`; }
  else { target = 0; reason = `mode=${mode}, band=${band} => OFF (unknown mode)`; }
}

// Minimum-change gating (marker-friendly)
const lastTarget = Number(flow.get('stair_last_target'));
flow.set('stair_last_target', target);

const delta = Number.isFinite(lastTarget) ? Math.abs(target - lastTarget) : 999;

// If we're in marker territory (<=6%), allow 1% steps. Otherwise require 5%.
const minStep = (target <= 6 || lastTarget <= 6) ? 1 : 5;

if (Number.isFinite(lastTarget) && delta < minStep) return null;

msg.target_pct = target;
msg.reason = reason;
msg.topic = 'baseline';

flow.set("stair_baseline_pct", target);
flow.set("stair_baseline_reason", reason);

return msg;

// Gate Motion Bump (morning/night/away/vacation) + lux-adaptive bump + anti-loop lock

// 1) Only respond to motion ON
if (msg.payload !== "on") return null;

const manualUntil = Number(flow.get("stair_manual_until") || 0);
if (Date.now() < manualUntil) return null;

// 2) Mode gate
const mode = String(flow.get("stair_mode") || "unknown").toLowerCase();
const isMorning = mode.includes("morning");
const isNight = mode.includes("night") || mode.includes("sleep");
const isAway = mode.includes("away");
const isVacation = mode.includes("vacation");

if (!(isMorning || isNight || isAway || isVacation)) return null;

// 3) Optional: require motion to have been clear for 10s
const lastClear = Number(flow.get("stair_last_clear") || 0);
if (lastClear && (Date.now() - lastClear < 10000)) return null;

// 4) Lock: only one bump at a time
if (flow.get("stair_bump_active")) return null;
flow.set("stair_bump_active", true);
