// 5) Lux-adaptive bump brightness
const lux = Number(flow.get("stair_lux") || 0);

let bump;
if (lux < 2) bump = 25;
else if (lux < 10) bump = 35;
else if (lux < 30) bump = 45;
else bump = 55;

// Cap by mode
if (isNight) bump = Math.min(bump, 25);
if (isMorning) bump = Math.min(bump, 30);

msg.bump_pct = bump;
msg.transition = 0.8;
msg.bump_seconds = 90;
msg.reason = `motion bump: mode=${mode}, lux=${lux} => ${bump}% for ${msg.bump_seconds}s`;

return msg;

// Trigger a baseline recompute using the latest stored lux/mode
const mode = flow.get('stair_mode');
const lux  = flow.get('stair_lux');
if (typeof mode === 'undefined' || typeof lux === 'undefined') return null;

return { topic: 'lux', payload: Number(lux) };

// Detect Manual Override for stairwell nightlight
// Requires your Mark Auto Action node to set flow.stair_last_auto_ts when NR changes the light.

const now = Date.now();
const lastAuto = Number(flow.get("stair_last_auto_ts") || 0);
const AUTO_WINDOW_MS = 5000;          // if our automation acted in last 5s, ignore
const OVERRIDE_MINUTES = 10;
const OVERRIDE_MS = OVERRIDE_MINUTES * 60 * 1000;

const newState = msg.payload; // with events: state, this is usually "on"/"off"
if (typeof newState !== "string") return null;

// If Node-RED just acted, don't treat as manual
if (now - lastAuto < AUTO_WINDOW_MS) return null;

if (newState === "off") {
  flow.set("stair_manual_until", now + OVERRIDE_MS);
  node.status({fill:"yellow",shape:"dot",text:`manual override ${OVERRIDE_MINUTES}m`});
  return null;
}

if (newState === "on") {
  // Optional: treat manual ON as override too (prevents NR from dimming right away)
  flow.set("stair_manual_until", now + OVERRIDE_MS);
  node.status({fill:"yellow",shape:"dot",text:`manual override ${OVERRIDE_MINUTES}m (manual on)`});
  return null;
}

return null;

// Set Fade Target (after bump)
// Pull the latest computed baseline from context and prepare a fade-down.

const baseline = Number(flow.get("stair_baseline_pct"));
if (!Number.isFinite(baseline)) return null;

msg.target_pct = baseline;
msg.transition = 1.8;  // high-end fade-down timing
msg.reason = `fade down => baseline ${baseline}%`;
msg.topic = "baseline_fade";
return msg;

// Morning Living Room Trigger Gate
// Triggered by stairwell motion

if (msg.payload !== "on") return null;

const mode = String(flow.get("stair_mode") || "unknown").toLowerCase();
if (!mode.includes("morning")) return null;

// Time window: 05:00–08:30
const now = new Date();
const mins = now.getHours() * 60 + now.getMinutes();
const start = 5 * 60;
const end = 8 * 60 + 30;
if (mins < start || mins > end) return null;

// Use stairwell lux as a coarse gate
const stairLux = Number(flow.get("stair_lux") || 0);
if (stairLux > 60) return null;

// Cooldown
const nowMs = Date.now();
const last = Number(flow.get("livingroom_morning_last") || 0);
if (nowMs - last < 20 * 60 * 1000) return null;

flow.set("livingroom_morning_last", nowMs);

// Soft morning profile
let brightness = 22;
if (stairLux < 5) brightness = 18;
else if (stairLux < 15) brightness = 22;
else if (stairLux < 40) brightness = 28;
else brightness = 22;

msg.payload = "on";
msg.mode = mode;
msg.force_recalc = true;
msg.brightness_pct = Number(brightness);
msg.transition = 2;
msg.reason = `LR morning trigger: mode=${mode}, stairLux=${stairLux}, brightness=${brightness}%`;

return msg;

// LR Presence Gate - Weather Brain aware with pressure hysteresis
node.warn({ gate_entry: true, payload: msg.payload, topic: msg.topic, force_recalc: msg.force_recalc, mode: msg.mode });
if (msg.payload !== "on") return null;

const ha = global.get("homeassistant") || {};
const states = ha.homeAssistant?.states || {};

const mode = String(
  msg.mode ||
  states["input_select.jarvis_mode"]?.state ||
  flow.get("jarvis_mode") ||
  "unknown"
).toLowerCase();

const isDay = mode.includes("day");
const isEvening = mode.includes("evening");
const isNight = mode.includes("night") || mode.includes("sleep");

const isMorning = mode.includes("morning");

// On explicit reading-mode-off recalc, don't block non-day/evening/night modes —
// the user is in the room and wants ambient back regardless of mode.
if (!msg.force_recalc && !(isDay || isEvening || isNight || isMorning)) return null;
if (!msg.force_recalc && isMorning) return null; // morning handled by other logic unless explicit

const manualUntil = Number(flow.get("livingroom_manual_until") || 0);
if (Date.now() < manualUntil) return null;

const lux = Number(flow.get("lr_hue_lux") || 0);
const roomActive = !!flow.get("lr_presence_active");
const now = Date.now();
const prevHit = Number(flow.get("lr_hue_prev_hit") || 0);
const repeatedHit = prevHit && (now - prevHit < 30000);

flow.set("lr_hue_prev_hit", now);

// In evening/night, trust first hit after room has been empty
// (anti-false-positive is less important than responsiveness after dark)
const pendingHit = Number(flow.get("lr_hue_pending_hit") || 0);
const pendingRecent = pendingHit && (now - pendingHit < 90000);
const firstHitAfterDark = (isEvening || isNight) && !roomActive && pendingRecent;

// Preserve your anti-false-positive motion logic
if (!(roomActive || repeatedHit || firstHitAfterDark || msg.force_recalc === true)) {
  flow.set("lr_hue_pending_hit", now);
  return null;
}

flow.set("lr_presence_active", true);
flow.set("lr_presence_last_seen", now);

const readingMode =
  states["input_boolean.living_room_reading_mode"]?.state === "on";

if (readingMode) {
  msg.route = "hold";
  msg.reason = `LR automation standing down: reading mode active, mode=${mode}, lux=${lux}`;
  return msg;
}

const wbRainSoon =
  String(
    states["binary_sensor.weather_brain_rain_soon"]?.state ||
    flow.get("lr_weather_rain_soon") ||
    "off"
  ).toLowerCase() === "on";

const rawPressure =
  flow.get("lr_light_pressure") ??
  states["sensor.lr_light_pressure"]?.state ??
  0;

const lightPressure = Number(rawPressure);
const safePressure = Number.isFinite(lightPressure) ? lightPressure : 0;

// DAY MODE = Pressure-driven with hysteresis
if (isDay) {
  let brightness;
  let kelvin;

  const prevBand = String(flow.get("lr_day_pressure_band") || "unknown");
  let pressureBand = prevBand;

  // Hysteresis thresholds
  if (prevBand === "off") {
    if (safePressure > 22 && safePressure <= 48) pressureBand = "low";
    else if (safePressure > 48 && safePressure <= 78) pressureBand = "medium";
    else if (safePressure > 78) pressureBand = "high";
    else pressureBand = "off";
  } else if (prevBand === "low") {
    if (safePressure <= 12) pressureBand = "off";
    else if (safePressure > 48 && safePressure <= 78) pressureBand = "medium";
    else if (safePressure > 78) pressureBand = "high";
    else pressureBand = "low";
  } else if (prevBand === "medium") {
    if (safePressure <= 12) pressureBand = "off";
    else if (safePressure <= 34) pressureBand = "low";
    else if (safePressure > 78) pressureBand = "high";
    else pressureBand = "medium";
  } else if (prevBand === "high") {
    if (safePressure <= 12) pressureBand = "off";
    else if (safePressure <= 34) pressureBand = "low";
    else if (safePressure <= 62) pressureBand = "medium";
    else pressureBand = "high";
  } else {
    // No prior band yet: use clean entry thresholds
    if (safePressure <= 15) pressureBand = "off";
    else if (safePressure <= 40) pressureBand = "low";
    else if (safePressure <= 70) pressureBand = "medium";
    else pressureBand = "high";
  }

  // Optional temporal hysteresis: prevent rapid band oscillation
  const nowTs = Date.now();
  const lastBandTs = Number(flow.get("lr_day_pressure_band_ts") || 0);
  const bandChanged = pressureBand !== prevBand;

  if (
    bandChanged &&
    prevBand !== "unknown" &&
    msg.topic !== "reading_mode_off_recalc" &&
    msg.topic !== "lr_day_recalc" &&
    msg.topic !== "lr_motion_on" &&
    (nowTs - lastBandTs) < 180000
  ) {
    pressureBand = prevBand;
  }

  if (pressureBand !== prevBand) {
    flow.set("lr_day_pressure_band_ts", nowTs);
  }

  flow.set("lr_day_pressure_band", pressureBand);

  if (pressureBand === "off") {
    msg.route = "off";
    msg.transition = msg.transition || 2;
    msg.reason = `LR day off: pressure=${safePressure}, band=${pressureBand}, prev=${prevBand}`;
    return msg;
  } else if (pressureBand === "low") {
    brightness = wbRainSoon ? 32 : 24;
    kelvin = wbRainSoon ? 3200 : 3500;
  } else if (pressureBand === "medium") {
    brightness = wbRainSoon ? 48 : 40;
    kelvin = wbRainSoon ? 3000 : 3300;
  } else {
    brightness = wbRainSoon ? 68 : 58;
    kelvin = wbRainSoon ? 2800 : 3000;
  }

  const lastBrightness = Number(flow.get("lr_last_brightness"));
  const lastKelvin = Number(flow.get("lr_last_kelvin"));

  if (
    lastBrightness === brightness &&
    lastKelvin === kelvin &&
    msg.topic !== "reading_mode_off_recalc"
  ) {
    return null;
  }

  flow.set("lr_last_brightness", brightness);
  flow.set("lr_last_kelvin", kelvin);

  msg.route = "ambient";
  msg.brightness_pct = brightness;
  msg.color_temp_kelvin = kelvin;
  msg.transition = msg.transition || 2;
  msg.reason =
    `LR day adaptive: pressure=${safePressure}, band=${pressureBand}, prev=${prevBand}, ` +
    `rain_soon=${wbRainSoon}, brightness=${brightness}%, kelvin=${kelvin}`;

  return msg;
}

// EVENING / NIGHT = preserve current lux-based comfort model
let brightness = 85 - (lux * 0.7);

if (isNight) {
  brightness -= 20;
}

if (isEvening) {
  brightness = Math.min(55, Math.max(30, brightness));
} else if (isNight) {
  brightness = Math.min(22, Math.max(10, brightness));
}

brightness = Math.round(brightness);

const lastBrightness = Number(flow.get("lr_last_brightness"));
if (lastBrightness === brightness && msg.topic !== "reading_mode_off_recalc") {
  return null;
}

flow.set("lr_last_brightness", brightness);
flow.set("lr_last_kelvin", 3000);

msg.route = "ambient";
msg.brightness_pct = brightness;
msg.color_temp_kelvin = isNight ? 2700 : 3000;
msg.transition = msg.transition || 1.5;
msg.reason = `LR adaptive lighting: mode=${mode}, lux=${lux}, brightness=${brightness}%`;

return msg;

flow.set("livingroom_last_auto_ts", Date.now());

// Ensure numeric values for HA action node
if (msg.brightness_pct !== undefined) {
  msg.brightness_pct = Number(msg.brightness_pct);
}
if (msg.target_pct !== undefined) {
  msg.target_pct = Number(msg.target_pct);
}
if (msg.transition !== undefined) {
  msg.transition = Number(msg.transition);
}
if (msg.color_temp_kelvin !== undefined) {
  msg.color_temp_kelvin = Number(msg.color_temp_kelvin);
}

return msg;

const active = !!flow.get("lr_presence_active");
if (!active) return null;

const lastSeen = Number(flow.get("lr_presence_last_seen") || 0);
if (!lastSeen) return null;

const now = Date.now();
const holdMs = 45 * 60 * 1000;   // 45 min hold

if (now - lastSeen < holdMs) return null;

flow.set("lr_presence_active", false);

const ha = global.get("homeassistant") || {};
const states = ha.homeAssistant?.states || {};

const mode = String(
  states["input_select.jarvis_mode"]?.state || "unknown"
).toLowerCase();

const isEvening = mode.includes("evening");

if (isEvening) {
  msg.target_pct = 10;
  msg.transition = 3;
  msg.action = "dim";
  msg.reason = "LR presence expired => dim to evening ambient";
} else {
  msg.action = "off";
  msg.transition = 3;
  msg.reason = "LR presence expired => off";
}

return msg;

const roomActive = !!flow.get("lr_presence_active");

const ha = global.get("homeassistant") || {};
const states = ha.homeAssistant?.states || {};

const jarvisMode = String(
  states["input_select.jarvis_mode"]?.state ||
  flow.get("jarvis_mode") ||
  "unknown"
).toLowerCase();

const readingMode = flow.get("lr_reading_mode");

node.warn({ recalc_fired: true,
  source: msg.topic || "unknown",
  roomActive,
  jarvisMode,
  readingMode
});

// If reading mode was explicitly turned off, treat as occupied regardless —
// the user is clearly in the room if they issued the voice command.
const explicitReadingModeOff = (msg.topic === "input_boolean.living_room_reading_mode" || !!msg.force_reading_off);

if (!roomActive && !explicitReadingModeOff) return null;
if (readingMode === true || readingMode === "on") return null;
if (jarvisMode === "unknown") return null;

// Ensure presence is active since user is clearly home
flow.set("lr_presence_active", true);
flow.set("lr_presence_last_seen", Date.now());

// Reset cached brightness/kelvin so the gate always applies the light call
// (HA deduplicates light.turn_on silently if values haven't changed)
flow.set("lr_last_brightness", -1);
flow.set("lr_last_kelvin", -1);

msg.payload = "on";
msg.topic = "reading_mode_off_recalc";
msg.mode = jarvisMode;
msg.force_recalc = true;
msg.reason = "Reading mode turned off; recalculating ambient lighting.";
msg.transition = 2;

return msg;

const roomActive = !!flow.get("lr_presence_active");
if (!roomActive) return null;

const manualUntil = Number(flow.get("livingroom_manual_until") || 0);
if (Date.now() < manualUntil) return null;

const ha = global.get("homeassistant") || {};
const states = ha.homeAssistant?.states || {};

const readingMode =
  states["input_boolean.living_room_reading_mode"]?.state === "on";
if (readingMode) return null;

const lux = Number(flow.get("lr_hue_lux") || 0);
const lastTriggerLux = Number(flow.get("lr_last_recalc_lux") ?? -1);

// Only react if lux changed meaningfully
if (lastTriggerLux >= 0 && Math.abs(lux - lastTriggerLux) < 5) {
  return null;
}

flow.set("lr_last_recalc_lux", lux);

msg.payload = "on";
msg.topic = "lr_lux_recalc";
msg.mode = states["input_select.jarvis_mode"]?.state || "unknown";
msg.force_recalc = true;
msg.reason = `Living room lux changed while occupied; lux=${lux}`;

return msg;

flow.set("livingroom_last_auto_ts", Date.now());
flow.set("lr_presence_active", true);
flow.set("lr_presence_last_seen", Date.now());
msg.reason = "LR reading mode ON => activating scene.lr_reading and marking room active";
return msg;

const raw = String(msg.payload || "off").toLowerCase();
const isOn = (raw === "on" || raw === "true");
flow.set("lr_reading_mode", isOn);

// When reading mode turns off, clear manual override so automation re-engages immediately
if (!isOn) {
  flow.set("livingroom_manual_until", 0);
  msg.reason = "reading mode OFF → manual override cleared, recalc queued";
}

return msg;

const ha = global.get("homeassistant") || {};
const states = ha.homeAssistant?.states || {};

const manualUntil = Number(flow.get("livingroom_manual_until") || 0);
if (Date.now() < manualUntil) return null;

const jarvisMode = String(states["input_select.jarvis_mode"]?.state || "unknown").toLowerCase();
if (!jarvisMode.includes("evening")) return null;

const roomActive = !!flow.get("lr_presence_active");
if (!roomActive) return null;

const readingMode = String(states["input_boolean.living_room_reading_mode"]?.state || "off").toLowerCase();
if (readingMode === "on") return null;

msg.payload = "on";
msg.topic = "lr_evening_recalc";
msg.mode = "evening";
msg.force_recalc = true;
msg.reason = "Jarvis mode switched to evening; recalculating living room ambient.";
msg.transition = 3;

return msg;

if (msg.garage_state !== undefined) flow.set('gnv3_garage_state', msg.garage_state);
if (msg.front_door_state !== undefined) flow.set('gnv3_front_door_state', msg.front_door_state);

const g = flow.get('gnv3_garage_state') || 'unknown';
const f = flow.get('gnv3_front_door_state') || 'unknown';

let issues = [];
if (g === 'open' || g === 'opening') issues.push('garage is open');
if (f === 'on' || f === 'open') issues.push('front door is open');

msg.good_night_summary = issues.length
  ? `Good Night completed, but ${issues.join(' and ')}.`
  : 'Good Night completed. House is in night mode.';

return msg;

const ha = global.get("homeassistant") || {};
const states = ha.homeAssistant?.states || {};

const jarvisMode = String(states["input_select.jarvis_mode"]?.state || "unknown").toLowerCase();
if (!jarvisMode.includes("day")) return null;

// If nobody is in the room, don't proactively turn it on
const roomActive = !!flow.get("lr_presence_active");
if (!roomActive) return null;

const readingMode = String(states["input_boolean.living_room_reading_mode"]?.state || "off").toLowerCase();
if (readingMode === "on") return null;

msg.payload = "on";
msg.topic = "lr_day_recalc";
msg.mode = "day";
msg.force_recalc = true;
msg.transition = 2;
msg.reason = "Jarvis mode switched to day; recalculating living room adaptive lighting.";

return msg;

const ha = global.get("homeassistant") || {};
const states = ha.homeAssistant?.states || {};

const manualUntil = Number(flow.get("livingroom_manual_until") || 0);
if (Date.now() < manualUntil) return null;

const roomActive = !!flow.get("lr_presence_active");
const lrOn = states["light.living_room"]?.state === "on";

if (!(roomActive || lrOn)) return null;

const jarvisMode = String(
  states["input_select.jarvis_mode"]?.state || "unknown"
).toLowerCase();

if (!jarvisMode.includes("day")) return null;

const readingMode = String(
  states["input_boolean.living_room_reading_mode"]?.state || "off"
).toLowerCase();

if (readingMode === "on") return null;

flow.set(
  "lr_weather_light_class",
  String(states["sensor.weather_brain_light_class"]?.state || "normal").toLowerCase()
);

flow.set(
  "lr_weather_rain_soon",
  String(states["binary_sensor.weather_brain_rain_soon"]?.state || "off").toLowerCase()
);

flow.set(
  "lr_light_pressure",
  Number(states["sensor.lr_light_pressure"]?.state || 0)
);

msg.payload = "on";
msg.topic = "lr_weather_recalc";
msg.mode = jarvisMode;
msg.force_recalc = true;
msg.transition = 2;
msg.reason = "Weather Brain changed while LR active/lit in day mode; recalculating.";

return msg;

const entityId =
  msg.data?.entity_id ||
  msg.data?.new_state?.entity_id ||
  "";

if (entityId === "sensor.weather_brain_light_class") {
  flow.set("lr_weather_light_class", String(msg.payload || "normal").toLowerCase());
}

if (entityId === "binary_sensor.weather_brain_rain_soon") {
  flow.set("lr_weather_rain_soon", String(msg.payload || "off").toLowerCase());
}

if (entityId === "sensor.lr_light_pressure") {
  const p = Number(msg.payload);
  flow.set("lr_light_pressure", Number.isFinite(p) ? p : 0);
}

return msg;

// Day mode whole-house lighting reset
// Intentionally EXCLUDES:
// - office lights
// - living room light (handled by LR weather/presence adaptive logic)

msg.payload = {
  entity_id: [
    "light.night_light_stairwell",
    "light.primary_bdrm_lamp_1",
    "light.primary_bdrm_lamp_2",
    "light.kennedys_bedroom"
  ],
  transition: 2
};

msg.reason = "Jarvis mode changed to day: turning off whole-house lights except office and living room.";
return msg;

const now = Date.now();
flow.set("stair_last_auto_ts", now);
flow.set("primary_bedroom_last_auto_ts", now);
flow.set("kennedy_bedroom_last_auto_ts", now);
return msg;

const ha = global.get("homeassistant") || {};
const states = ha.homeAssistant?.states || {};

const mode = String(
  states["input_select.jarvis_mode"]?.state ?? msg.payload ?? "unknown"
).toLowerCase().trim();

const luxRaw = states["sensor.wave_enhance_master_br_illuminance"]?.state;
const luxNum = Number(luxRaw);
const lux = Number.isFinite(luxNum) ? luxNum : 999;

const readingMode =
  states["input_boolean.primary_bedroom_reading_mode"]?.state === "on";

const light1 = states["light.primary_bdrm_lamp_1"]?.state || "unknown";
const light2 = states["light.primary_bdrm_lamp_2"]?.state || "unknown";
const anyLightOn = (light1 === "on" || light2 === "on");

const manualUntil = Number(flow.get("primary_bedroom_manual_until") || 0);
const manualActive = Date.now() < manualUntil;

// track last evaluated lux for debug / future logic
flow.set("primary_bedroom_last_lux", lux);

node.warn({
  source: "Primary Bdrm Mode Gate",
  trigger_topic: msg.topic || "unknown",
  mode,
  luxRaw,
  lux,
  readingMode,
  light1,
  light2,
  anyLightOn,
  manualUntil,
  manualActive
});

// DAY: always turn off and clear stale manual override
if (mode.includes("day")) {
  flow.set("primary_bedroom_manual_until", 0);
  msg.action = "off";
  msg.transition = 3;
  msg.reason = "Primary bedroom: Jarvis Day => turning lights off";
  return msg;
}

// Only manage auto-on during evening
if (!mode.includes("evening")) {
  return null;
}

// Respect manual override
if (manualActive) {
  msg.reason = `Primary bedroom: evening auto-on suppressed by manual override until ${new Date(manualUntil).toLocaleTimeString()}`;
  return null;
}

// Respect reading mode
if (readingMode) {
  msg.reason = "Primary bedroom: evening auto-on suppressed by reading mode";
  return null;
}

// Do not reassert if already on
if (anyLightOn) {
  msg.reason = "Primary bedroom: evening auto-on skipped because a lamp is already on";
  return null;
}

// Evening auto-on: JARVIS mode is the authority, lux drives brightness only
let brightness;
if (lux < 8) brightness = 40;
else if (lux < 25) brightness = 32;
else if (lux < 60) brightness = 25;
else brightness = 20;

msg.action = "on";
msg.brightness_pct = brightness;
msg.transition = 3;
msg.reason = `Primary bedroom evening ambient: lux=${lux}, brightness=${brightness}%`;
return msg;

const lastAuto = Number(flow.get("primary_bedroom_last_auto_ts") || 0);
const now = Date.now();

const AUTO_WINDOW_MS = 15000;      // was effectively 5000
const OVERRIDE_MS = 15 * 60 * 1000; // 15 min instead of 30

// Ignore changes caused by our own automation
if (lastAuto && (now - lastAuto < AUTO_WINDOW_MS)) return null;

// Only set manual override for real on/off state changes
if (msg.payload !== "on" && msg.payload !== "off") return null;

flow.set("primary_bedroom_manual_until", now + OVERRIDE_MS);
msg.reason = `Primary bedroom manual override detected on ${msg.topic}; suppressing evening auto-on for 15min`;
return msg;

const ha = global.get("homeassistant") || {};
const states = ha.homeAssistant?.states || {};

const mode = String(
  msg.payload ?? states["input_select.jarvis_mode"]?.state ?? "unknown"
).toLowerCase().trim();

const lightState = states["light.kennedys_bedroom"]?.state || "unknown";
const isOn = (lightState === "on");

// DAY: always attempt off, and clear stale evening manual override
if (mode === "day" || mode.includes("day")) {
  flow.set("kennedy_bedroom_manual_until", 0);
  msg.action = "off";
  msg.transition = 3;
  msg.reason = "Kennedy bedroom: Jarvis Day => turning lights off";
  return msg;
}

// Only auto-on in evening
if (!(mode === "evening" || mode.includes("evening"))) {
  return null;
}

// Respect manual override for evening auto-on
const manualUntil = Number(flow.get("kennedy_bedroom_manual_until") || 0);
if (Date.now() < manualUntil) {
  msg.reason = `Kennedy bedroom: evening auto-on suppressed by manual override until ${new Date(manualUntil).toLocaleTimeString()}`;
  return null;
}

// If already on, don't reassert
if (isOn) {
  msg.reason = "Kennedy bedroom: evening auto-on skipped because light is already on";
  return null;
}

msg.action = "on";
msg.brightness_pct = 28;
msg.transition = 3;
msg.reason = "Kennedy bedroom evening ambient => brightness 28%";
return msg;

const lastAuto = Number(flow.get("kennedy_bedroom_last_auto_ts") || 0);
const now = Date.now();

// Ignore changes caused by our own automation
if (lastAuto && (now - lastAuto < 5000)) return null;

flow.set("kennedy_bedroom_manual_until", now + (2 * 60 * 60 * 1000));
msg.reason = `Kennedy bedroom manual override detected; suppressing evening auto-on for 2h`;
return msg;

const lastAuto = Number(flow.get("livingroom_last_auto_ts") || 0);
const now = Date.now();
const AUTO_WINDOW_MS = 5000;
const OVERRIDE_MS = 15 * 60 * 1000;

// If light turned off manually
if (msg.payload === "off" || msg.payload === false) {
    const isReadingMode = flow.get("lr_reading_mode");
    if (isReadingMode) {
        // Reading mode was on — clear it and the override
        flow.set("lr_reading_mode", false);
        flow.set("livingroom_manual_until", 0);
        msg.reason = "LR light turned off → clearing reading mode and manual override";
        return [null, msg];
    }
    // No reading mode — treat manual off as a 15-min override so motion
    // doesn't immediately turn lights back on
    flow.set("livingroom_manual_until", now + OVERRIDE_MS);
    msg.reason = "LR light turned off manually → suppressing automation for 15 min";
    return [msg, null];
}

// Light turned on manually — check if it was triggered by automation
if (lastAuto && (now - lastAuto < AUTO_WINDOW_MS)) return null;
flow.set("livingroom_manual_until", now + OVERRIDE_MS);
msg.reason = "LR manual override detected → suppressing automation for 15 min";
return [msg, null];

flow.set("lr_reading_mode", false);
flow.set("livingroom_manual_until", 0);

// If JARVIS switched to night, also expire presence so stray motion doesn't
// re-trigger full brightness lighting
const ha = global.get("homeassistant") || {};
const states = ha.homeAssistant?.states || {};
const mode = String(states["input_select.jarvis_mode"]?.state || "").toLowerCase();
if (mode.includes("night")) {
  flow.set("lr_presence_active", false);
  flow.set("lr_presence_last_seen", 0);
}

msg.reason = "JARVIS mode changed → reading mode and manual override cleared";
return msg;

const raw = msg.payload;
const open = (raw === 'on' || raw === 'open' || raw === true);
msg.payload = {
    door: 'Front Door',
    entity_id: 'binary_sensor.front_door_contact',
    raw_state: raw,
    state: open ? 'open' : 'closed',
    open,
    ts: Date.now(),
    when: new Date().toLocaleString()
};
msg.topic = msg.payload.entity_id;
msg._doorEvent = RED.util.cloneMessage(msg.payload);
return msg;

const raw = msg.payload;
const open = (raw === 'on' || raw === 'open' || raw === true);
msg.payload = {
    door: 'Garage Door',
    entity_id: 'binary_sensor.garage_door_contact',
    raw_state: raw,
    state: open ? 'open' : 'closed',
    open,
    ts: Date.now(),
    when: new Date().toLocaleString()
};
msg.topic = msg.payload.entity_id;
msg._doorEvent = RED.util.cloneMessage(msg.payload);
return msg;

const raw = msg.payload;
const open = (raw === 'on' || raw === 'open' || raw === true);
msg.payload = {
    door: 'Garage Overhead Door',
    entity_id: 'binary_sensor.garage_overhead_door',
    raw_state: raw,
    state: open ? 'open' : 'closed',
    open,
    ts: Date.now(),
    when: new Date().toLocaleString()
};
msg.topic = msg.payload.entity_id;
msg._doorEvent = RED.util.cloneMessage(msg.payload);
return msg;

const raw = msg.payload;
const open = (raw === 'on' || raw === 'open' || raw === true);
msg.payload = {
    door: 'Patio Door',
    entity_id: 'binary_sensor.patio_door_contact',
    raw_state: raw,
    state: open ? 'open' : 'closed',
    open,
    ts: Date.now(),
    when: new Date().toLocaleString()
};
msg.topic = msg.payload.entity_id;
msg._doorEvent = RED.util.cloneMessage(msg.payload);
return msg;

if (!msg.alert) return null;

const a = msg.alert;
let spoken = a.message;

// Normalize spoken text by alert type
if (a.type === 'warning' && a.repeat) {
    spoken = `Reminder. ${a.zone_label} is still open.`;
}

if (a.type === 'critical' && a.repeat) {
    spoken = `Critical repeat. ${a.zone_label} is still open.`;
}

msg.payload = {
    message: spoken
};

msg.tts_text = spoken;

// Important: let repeats bypass RBE duplicate suppression by changing topic
if (a.repeat) {
    msg.topic = `tts_repeat_${a.zone}_${Date.now()}`;
} else {
    msg.topic = `tts_${a.zone}_${a.type}`;
}

return msg;

const topic = String(msg.topic || "");
const payload = msg.payload;

if (topic === "tick") {
    msg.posture_update = { kind: "tick" };
    return msg;
}

if (topic === "jarvis/presence/state") {
    msg.posture_update = { kind: "presence_state", value: String(payload || "") };
    return msg;
}

if (topic === "jarvis/presence/confidence") {
    msg.posture_update = { kind: "presence_confidence", value: Number(payload || 0) };
    return msg;
}

if (topic === "jarvis/presence/people_detail") {
    try {
        msg.posture_update = {
            kind: "people_detail",
            value: typeof payload === "string" ? JSON.parse(payload) : payload
        };
        return msg;
    } catch (e) {
        return null;
    }
}

msg.posture_update = {
    kind: "ha_state",
    name: topic,
    value: String(payload || "").toLowerCase()
};

return msg;

let s = flow.get("securityPostureState");

if (!s || typeof s !== "object" || Array.isArray(s)) {
    s = {
        front_door: "off",
        patio_door: "off",
        overhead_door: "off",
        garage_door: "off",

        front_door_bypass: "off",
        patio_door_bypass: "off",
        overhead_door_bypass: "off",
        garage_door_bypass: "off",

        jarvis_mode: "home",

        presence_state: "Unknown",
        presence_confidence: 0,
        people_detail: {},
        trusted_home_count: 0,
        trusted_away_count: 0,
        trusted_unknown_count: 0,

        candidate_posture: null,
        candidate_since: 0,
        last_posture: null,
        updated_ts: 0
    };
}

const u = msg.posture_update || {};
const now = Date.now();

if (u.kind === "ha_state") {
    s[u.name] = u.value;
}

if (u.kind === "presence_state") {
    s.presence_state = String(u.value || "Unknown");
}

if (u.kind === "presence_confidence") {
    s.presence_confidence = Number(u.value || 0);
}

if (u.kind === "people_detail") {
    const pd = u.value && typeof u.value === "object" ? u.value : {};
    s.people_detail = pd;

    const vals = Object.values(pd);
    s.trusted_home_count = vals.filter(v => v?.trusted_state === "home").length;
    s.trusted_away_count = vals.filter(v => v?.trusted_state === "away").length;
    s.trusted_unknown_count = vals.filter(v => v?.trusted_state === "unknown").length;
}

s.updated_ts = now;

flow.set("securityPostureState", s);
msg.securityPostureState = s;
return msg;

let s = flow.get("securityPostureState");

if (!s || typeof s !== "object" || Array.isArray(s)) {
    return null;
}

const now = Date.now();
const STABILITY_MS = 15 * 1000;

function isOpen(v) {
    return ["on", "open", "opening", "true"].includes(String(v || "").toLowerCase());
}

const frontOpen = isOpen(s.front_door);
const patioOpen = isOpen(s.patio_door);
const overheadOpen = isOpen(s.overhead_door);
const garageDoorOpen = isOpen(s.garage_door);

const frontBypassed = s.front_door_bypass === "on";
const patioBypassed = s.patio_door_bypass === "on";
const overheadBypassed = s.overhead_door_bypass === "on";
const garageDoorBypassed = s.garage_door_bypass === "on";

const frontBreach = frontOpen && !frontBypassed;
const patioBreach = patioOpen && !patioBypassed;
const overheadBreach = overheadOpen && !overheadBypassed;
const garageDoorBreach = garageDoorOpen && !garageDoorBypassed;

const breachedZones = [];
if (frontBreach) breachedZones.push("front_door");
if (patioBreach) breachedZones.push("patio_door");
if (overheadBreach) breachedZones.push("overhead_door");
if (garageDoorBreach) breachedZones.push("garage_door");

const openZones = [];
if (frontOpen) openZones.push("front_door");
if (patioOpen) openZones.push("patio_door");
if (overheadOpen) openZones.push("overhead_door");
if (garageDoorOpen) openZones.push("garage_door");

const bypassedOpenZones = [];
if (frontOpen && frontBypassed) bypassedOpenZones.push("front_door");
if (patioOpen && patioBypassed) bypassedOpenZones.push("patio_door");
if (overheadOpen && overheadBypassed) bypassedOpenZones.push("overhead_door");
if (garageDoorOpen && garageDoorBypassed) bypassedOpenZones.push("garage_door");

const perimeterOpen = breachedZones.length > 0;
const mode = String(s.jarvis_mode || "home").toLowerCase();
const presenceState = String(s.presence_state || "Unknown");
const presenceConfidence = Number(s.presence_confidence || 0);
const trustedHome = Number(s.trusted_home_count || 0);
const trustedUnknown = Number(s.trusted_unknown_count || 0);

let candidatePosture = "Home";
let reason = "default";
let threat = false;

if (mode === "vacation") {
    if (perimeterOpen) {
        candidatePosture = "Alert";
        reason = "vacation_mode_with_perimeter_breach";
        threat = true;
    } else {
        candidatePosture = "Vacation";
        reason = "jarvis_mode=vacation";
    }
}
else if (perimeterOpen && trustedHome === 0) {
    candidatePosture = "Alert";
    reason = "perimeter_breach_without_trusted_occupant";
    threat = true;
}
else if (mode === "night" && trustedHome > 0) {
    if (perimeterOpen) {
        candidatePosture = "Caution";
        reason = "night_with_open_perimeter";
    } else {
        candidatePosture = "Night";
        reason = "night_with_trusted_occupants";
    }
}
else if (trustedHome > 0) {
    if (perimeterOpen) {
        candidatePosture = "Caution";
        reason = "trusted_home_but_perimeter_open";
    } else {
        candidatePosture = "Home";
        reason = "trusted_occupancy";
    }
}
else if (
    trustedUnknown > 0 ||
    presenceState === "Probable Occupancy"
) {
    if (perimeterOpen) {
        candidatePosture = "Alert";
        reason = "ambiguous_occupancy_with_perimeter_breach";
        threat = true;
    } else {
        candidatePosture = "Caution";
        reason = "ambiguous_occupancy";
    }
}
else if (presenceState === "Unknown") {
    candidatePosture = "Away";
    reason = "presence_unknown_but_no_ambiguity_evidence";
}
else {
    candidatePosture = "Away";
    reason = perimeterOpen ? "away_with_breach" : "no_trusted_occupancy_and_secure";
    if (perimeterOpen) {
        threat = true;
        candidatePosture = "Alert";
    }
}

if (s.candidate_posture !== candidatePosture) {
    s.candidate_posture = candidatePosture;
    s.candidate_since = now;
}

let committedPosture = s.last_posture || candidatePosture;

if ((now - Number(s.candidate_since || 0)) >= STABILITY_MS || !s.last_posture) {
    committedPosture = s.candidate_posture;
}

const changed = committedPosture !== s.last_posture;

s.last_posture = committedPosture;
flow.set("securityPostureState", s);

msg.payload = committedPosture;
msg.reason = reason;
msg.posture_changed = changed;

msg.security = {
    posture: committedPosture,
    candidate_posture: candidatePosture,
    candidate_age_ms: now - Number(s.candidate_since || now),
    reason,
    threat,
    jarvis_mode: mode,
    presence_state: presenceState,
    presence_confidence: presenceConfidence,
    trusted_home_count: trustedHome,
    trusted_unknown_count: trustedUnknown,
    perimeter_open: perimeterOpen,
    open_zones: openZones,
    breached_zones: breachedZones,
    bypassed_open_zones: bypassedOpenZones,
    raw: s
};

node.status({
    fill: committedPosture === "Alert" ? "red"
        : committedPosture === "Caution" ? "yellow"
        : committedPosture === "Night" ? "blue"
        : committedPosture === "Away" ? "grey"
        : committedPosture === "Vacation" ? "purple"
        : "green",
    shape: "dot",
    text: `${committedPosture} | candidate: ${candidatePosture} | breach: ${breachedZones.join(",") || "none"}`
});

return msg;

return [
    { topic: "jarvis/posture/state", payload: msg.security.posture },
    { topic: "jarvis/posture/reason", payload: msg.security.reason },
    { topic: "jarvis/posture/threat", payload: String(!!msg.security.threat) }
];

if (msg.posture_changed) {
    node.warn(`POSTURE CHANGE → ${msg.security.posture} | reason: ${msg.security.reason}`);
}
return msg;

// Alert Engine v3
// Posture-driven, perimeter-aware, bypass-aware, repeat-capable

let s = flow.get('alertEngineState');

if (!s || typeof s !== 'object' || Array.isArray(s)) {
    s = {};
}

// enforce structure
s.front_door = (s.front_door ?? 'off').toString().toLowerCase();
s.patio_door = (s.patio_door ?? 'off').toString().toLowerCase();
s.overhead_door = (s.overhead_door ?? 'off').toString().toLowerCase();
s.garage_door = (s.garage_door ?? 'off').toString().toLowerCase();

s.front_door_bypass = (s.front_door_bypass ?? 'off').toString().toLowerCase();
s.patio_door_bypass = (s.patio_door_bypass ?? 'off').toString().toLowerCase();
s.overhead_door_bypass = (s.overhead_door_bypass ?? 'off').toString().toLowerCase();
s.garage_door_bypass = (s.garage_door_bypass ?? 'off').toString().toLowerCase();

s.security_posture = (s.security_posture ?? 'home').toString().toLowerCase();

s.opened_at = (s.opened_at && typeof s.opened_at === 'object' && !Array.isArray(s.opened_at)) ? s.opened_at : {};
s.last_warn_at = (s.last_warn_at && typeof s.last_warn_at === 'object' && !Array.isArray(s.last_warn_at)) ? s.last_warn_at : {};
s.last_repeat_at = (s.last_repeat_at && typeof s.last_repeat_at === 'object' && !Array.isArray(s.last_repeat_at)) ? s.last_repeat_at : {};
s.last_crit_at = (s.last_crit_at && typeof s.last_crit_at === 'object' && !Array.isArray(s.last_crit_at)) ? s.last_crit_at : {};
s.warning_sent = (s.warning_sent && typeof s.warning_sent === 'object' && !Array.isArray(s.warning_sent)) ? s.warning_sent : {};
s.critical_sent = (s.critical_sent && typeof s.critical_sent === 'object' && !Array.isArray(s.critical_sent)) ? s.critical_sent : {};
s.clear_sent = (s.clear_sent && typeof s.clear_sent === 'object' && !Array.isArray(s.clear_sent)) ? s.clear_sent : {};

// update state
if (msg.topic && msg.topic !== 'tick' && Object.prototype.hasOwnProperty.call(s, msg.topic)) {
    s[msg.topic] = (msg.payload ?? '').toString().toLowerCase();
}

function isOpen(v) {
    return ['on', 'open', 'opening', 'true'].includes((v ?? '').toString().toLowerCase());
}

const now = Date.now();
const posture = (s.security_posture ?? 'home').toString().toLowerCase();

const zoneConfig = {
    front_door: {
        label: 'Front door',
        warningMs: 60 * 1000,
        repeatWarnMs: 60 * 1000,
        repeatCritMs: 2 * 60 * 1000,
        bypass: s.front_door_bypass === 'on'
    },
    patio_door: {
        label: 'Patio door',
        warningMs: 60 * 1000,
        repeatWarnMs: 60 * 1000,
        repeatCritMs: 2 * 60 * 1000,
        bypass: s.patio_door_bypass === 'on'
    },
    overhead_door: {
        label: 'Garage overhead door',
        warningMs: 5 * 60 * 1000,
        repeatWarnMs: 60 * 1000,
        repeatCritMs: 2 * 60 * 1000,
        bypass: s.overhead_door_bypass === 'on'
    },
    garage_door: {
        label: 'Garage door',
        warningMs: 60 * 1000,
        repeatWarnMs: 60 * 1000,
        repeatCritMs: 2 * 60 * 1000,
        bypass: s.garage_door_bypass === 'on'
    }
};

const zones = [
    {
        key: 'front_door',
        label: zoneConfig.front_door.label,
        open: isOpen(s.front_door),
        bypass: zoneConfig.front_door.bypass,
        warningMs: zoneConfig.front_door.warningMs,
        repeatWarnMs: zoneConfig.front_door.repeatWarnMs,
        repeatCritMs: zoneConfig.front_door.repeatCritMs
    },
    {
        key: 'patio_door',
        label: zoneConfig.patio_door.label,
        open: isOpen(s.patio_door),
        bypass: zoneConfig.patio_door.bypass,
        warningMs: zoneConfig.patio_door.warningMs,
        repeatWarnMs: zoneConfig.patio_door.repeatWarnMs,
        repeatCritMs: zoneConfig.patio_door.repeatCritMs
    },
    {
        key: 'overhead_door',
        label: zoneConfig.overhead_door.label,
        open: isOpen(s.overhead_door),
        bypass: zoneConfig.overhead_door.bypass,
        warningMs: zoneConfig.overhead_door.warningMs,
        repeatWarnMs: zoneConfig.overhead_door.repeatWarnMs,
        repeatCritMs: zoneConfig.overhead_door.repeatCritMs
    },
    {
        key: 'garage_door',
        label: zoneConfig.garage_door.label,
        open: isOpen(s.garage_door),
        bypass: zoneConfig.garage_door.bypass,
        warningMs: zoneConfig.garage_door.warningMs,
        repeatWarnMs: zoneConfig.garage_door.repeatWarnMs,
        repeatCritMs: zoneConfig.garage_door.repeatCritMs
    }
];

const criticalPostures = ['away', 'vacation', 'alert'];
const warningPostures = ['home', 'evening', 'night', 'caution'];

let outAlert = null;
let outTts = null;
let outDebug = null;

for (const z of zones) {
    if (z.open) {
        if (!s.opened_at[z.key]) s.opened_at[z.key] = now;
    } else {
        if (s.opened_at[z.key]) delete s.opened_at[z.key];
        if (s.last_warn_at[z.key]) delete s.last_warn_at[z.key];
        if (s.last_repeat_at[z.key]) delete s.last_repeat_at[z.key];
        if (s.last_crit_at[z.key]) delete s.last_crit_at[z.key];

        if (s.warning_sent[z.key] || s.critical_sent[z.key]) {
            if (!s.clear_sent[z.key]) {
                const clearMsg = {
                    alert: {
                        type: 'clear',
                        repeat: false,
                        zone: z.key,
                        zone_label: z.label,
                        posture,
                        push: true,
                        tts: false,
                        message: `${z.label} is now closed.`,
                        open_for_seconds: 0,
                        ts: new Date().toISOString()
                    }
                };
                outAlert = clearMsg;
                outDebug = RED.util.cloneMessage(clearMsg);
                s.clear_sent[z.key] = true;
            }
        }

        delete s.warning_sent[z.key];
        delete s.critical_sent[z.key];
        continue;
    }

    if (z.bypass) {
        continue;
    }

    s.clear_sent[z.key] = false;
    const openFor = now - (s.opened_at[z.key] || now);

    // CRITICAL posture path
    if (criticalPostures.includes(posture)) {
        const shouldSendInitial = !s.critical_sent[z.key];
        const shouldSendRepeat =
            s.critical_sent[z.key] &&
            (!s.last_crit_at[z.key] || (now - s.last_crit_at[z.key]) >= z.repeatCritMs);

        if (shouldSendInitial || shouldSendRepeat) {
            const crit = {
                alert: {
                    type: 'critical',
                    repeat: !shouldSendInitial,
                    zone: z.key,
                    zone_label: z.label,
                    posture,
                    push: true,
                    tts: true,
                    message: shouldSendInitial
                        ? `Critical. ${z.label} opened while security posture is ${posture}.`
                        : `Critical repeat. ${z.label} is still open while security posture is ${posture}.`,
                    open_for_seconds: Math.round(openFor / 1000),
                    ts: new Date().toISOString()
                }
            };

            s.critical_sent[z.key] = true;
            s.last_crit_at[z.key] = now;
            outAlert = crit;
            outTts = RED.util.cloneMessage(crit);
            outDebug = RED.util.cloneMessage(crit);
            break;
        }
    }

    // WARNING posture path
    if (warningPostures.includes(posture) && openFor >= z.warningMs && !s.warning_sent[z.key]) {
        const warn = {
            alert: {
                type: 'warning',
                repeat: false,
                zone: z.key,
                zone_label: z.label,
                posture,
                push: true,
                tts: posture === 'night' || posture === 'caution',
                message: `${z.label} has been left open for ${Math.round(openFor / 1000)} seconds.`,
                open_for_seconds: Math.round(openFor / 1000),
                ts: new Date().toISOString()
            }
        };

        s.warning_sent[z.key] = true;
        s.last_warn_at[z.key] = now;
        s.last_repeat_at[z.key] = now;
        outAlert = warn;
        if (warn.alert.tts) outTts = RED.util.cloneMessage(warn);
        outDebug = RED.util.cloneMessage(warn);
        break;
    }

    if (
        warningPostures.includes(posture) &&
        s.warning_sent[z.key] &&
        (!s.last_repeat_at[z.key] || (now - s.last_repeat_at[z.key]) >= z.repeatWarnMs)
    ) {
        const repeat = {
            alert: {
                type: 'repeat',
                repeat: true,
                zone: z.key,
                zone_label: z.label,
                posture,
                push: true,
                tts: posture === 'night' || posture === 'caution',
                message: `Reminder. ${z.label} is still open.`,
                open_for_seconds: Math.round(openFor / 1000),
                ts: new Date().toISOString()
            }
        };

        s.last_repeat_at[z.key] = now;
        outAlert = repeat;
        if (repeat.alert.tts) outTts = RED.util.cloneMessage(repeat);
        outDebug = RED.util.cloneMessage(repeat);
        break;
    }
}

if (!outDebug) {
    outDebug = {
        alert: {
            type: 'noop',
            posture,
            open_zones: zones.filter(z => z.open).map(z => z.key),
            bypassed_open_zones: zones.filter(z => z.open && z.bypass).map(z => z.key),
            message: 'No alert generated.',
            ts: new Date().toISOString()
        }
    };
}

flow.set('alertEngineState', s);

const activeOpen = zones.filter(z => z.open).map(z => z.key).join(',') || 'none';
node.status({
    fill: outAlert && outAlert.alert.type === 'critical' ? 'red'
        : outAlert && (outAlert.alert.type === 'warning' || outAlert.alert.type === 'repeat') ? 'yellow'
        : 'green',
    shape: 'dot',
    text: `${posture} | open: ${activeOpen}`
});

return [outAlert, outTts, outDebug];

const s = msg.security || {};

const openZones = Array.isArray(s.open_zones) ? s.open_zones : [];
const breachedZones = Array.isArray(s.breached_zones) ? s.breached_zones : [];
const bypassedZones = Array.isArray(s.bypassed_open_zones) ? s.bypassed_open_zones : [];

const openText = openZones.length ? openZones.join(", ") : "None";
const breachedText = breachedZones.length ? breachedZones.join(", ") : "None";
const bypassedText = bypassedZones.length ? bypassedZones.join(", ") : "None";

const presenceSummary = `${s.presence_state || "Unknown"} (${s.presence_confidence || "n/a"})`;
const summary = `${s.posture || "Unknown"} | ${s.reason || "No reason available"} | Open: ${openText}`;

return [
    { payload: s.reason || "No reason available" },
    { payload: openText },
    { payload: breachedText },
    { payload: bypassedText },
    { payload: summary },
    { payload: presenceSummary },
    { payload: s.candidate_posture || "Unknown" },
    { payload: String(Number(s.candidate_age_ms || 0)) }
];

const entity = msg.entity_id || msg.topic || "";
const state = String(msg.state || msg.payload || "").toLowerCase();

// Heartbeat path (explicit)
if (msg.payload === "tick") {
  msg.presence_update = {
    kind: "heartbeat",
    source_entity: "heartbeat",
    source_state: "tick"
  };
  return msg;
}

let update = {
  source_entity: entity,
  source_state: state
};

switch (entity) {
  // Phone tracker evidence
  case "device_tracker.phil_s_iphone_14_pro_max":
  case "person.phillip":
    update.person = "phillip";
    update.kind = "tracker";
    update.tracker_state = state;
    break;

  case "device_tracker.kristine_s_iphone_14_pro_max":
  case "person.kristine":
    update.person = "kristine";
    update.kind = "tracker";
    update.tracker_state = state;
    break;

  case "device_tracker.kennedys_iphone":
  case "person.kennedy":
    update.person = "kennedy";
    update.kind = "tracker";
    update.tracker_state = state;
    break;

  // UniFi / Wi-Fi evidence
  case "device_tracker.unifi_default_de_b4_f2_8a_dd_2e":
    update.person = "phillip";
    update.kind = "wifi";
    update.wifi_state = state;
    update.wifi_connected = (state === "home");
    break;

  case "device_tracker.unifi_default_ca_97_a7_fb_2d_45":
    update.person = "kennedy";
    update.kind = "wifi";
    update.wifi_state = state;
    update.wifi_connected = (state === "home");
    break;

  case "device_tracker.unifi_default_54_32_c7_e0_ba_25":
    update.person = "kristine";
    update.kind = "wifi";
    update.wifi_state = state;
    update.wifi_connected = (state === "home");
    break;

  // Motion
  case "binary_sensor.hue_motion_lr_occupancy":
    update.kind = "motion";
    update.motion = { room: "living_room", active: state === "on" };
    break;

  case "binary_sensor.night_light_stairwell_occupancy":
    update.kind = "motion";
    update.motion = { room: "stairwell", active: state === "on" };
    break;

  // Mode
  case "input_select.jarvis_mode":
    update.kind = "mode";
    update.jarvis_mode = state;
    break;

  default:
    return null;
}

msg.presence_update = update;
return msg;

let p = flow.get("presence_state");

if (!p || !p.people) {
