    last_heartbeat_ts: 0
  };
}

const u = msg.presence_update || {};
const now = Date.now();

// Heartbeat path: no state mutation except timestamp, but keep flow alive
if (u.kind === "heartbeat") {
  p.last_heartbeat_ts = now;
  flow.set("presence_state", p);
  msg.presence_state = p;
  return msg;
}

if (u.person && p.people[u.person]) {
  if (u.kind === "tracker" && u.tracker_state) {
    p.people[u.person].tracker_state = u.tracker_state;
    p.people[u.person].tracker_last_update_ts = now;
  }

  if (u.kind === "wifi") {
    if (u.wifi_state) {
      p.people[u.person].wifi_state = u.wifi_state;
    }
    if (typeof u.wifi_connected === "boolean") {
      p.people[u.person].wifi_connected = u.wifi_connected;
    }
    p.people[u.person].wifi_last_update_ts = now;
  }
}

if (u.jarvis_mode) {
  p.jarvis_mode = u.jarvis_mode;
}

if (u.motion && u.motion.room) {
  const prev = p.motion[u.motion.room];

  p.motion[u.motion.room] = u.motion.active;

  // Only update timestamp on transition to active
  if (u.motion.active && prev !== true) {
    p.motion_ts[u.motion.room] = now;
  }
}

flow.set("presence_state", p);
msg.presence_state = p;
return msg;

const p = flow.get("presence_state");

if (!p || !p.people) {
  return null;
}

const now = Date.now();

const TRACKER_STALE_MS = 2 * 60 * 60 * 1000; // 2 hours
const WIFI_STALE_MS = 10 * 60 * 1000;        // 10 minutes

function isFresh(ts, maxAge) {
  return (now - Number(ts || 0)) <= maxAge;
}

function trustPerson(personObj) {
  const trackerLastTs = Number(personObj.tracker_last_update_ts || 0);
  const wifiLastTs = Number(personObj.wifi_last_update_ts || 0);

  const trackerFresh = isFresh(trackerLastTs, TRACKER_STALE_MS);
  const wifiFresh = isFresh(wifiLastTs, WIFI_STALE_MS);

  const trackerState = String(personObj.tracker_state || "unknown");
  const wifiState = String(personObj.wifi_state || "unknown");
  const wifiConnected = personObj.wifi_connected === true;

  const ageTrackerMs = trackerLastTs ? (now - trackerLastTs) : null;
  const ageWifiMs = wifiLastTs ? (now - wifiLastTs) : null;

// Strongest positive evidence: fresh Wi-Fi connected
// BUT only if tracker is not confidently away
if (
  wifiFresh &&
  wifiConnected &&
  !["not_home", "away"].includes(trackerState)
) {
    return {
      trusted_state: "home",
      reason: "fresh_wifi_connected",
      tracker_state: trackerState,
      tracker_fresh: trackerFresh,
      tracker_last_update_ts: trackerLastTs,
      age_tracker_ms: ageTrackerMs,
      wifi_state: wifiState,
      wifi_connected: wifiConnected,
      wifi_fresh: wifiFresh,
      wifi_last_update_ts: wifiLastTs,
      age_wifi_ms: ageWifiMs
    };
  }

  // Fresh WiFi disconnected → departure is authoritative over lingering iOS tracker
  if (wifiFresh && !wifiConnected && trackerState === "home") {
    return {
      trusted_state: "away",
      reason: "fresh_wifi_disconnected_overrides_tracker",
      tracker_state: trackerState,
      tracker_fresh: trackerFresh,
      tracker_last_update_ts: trackerLastTs,
      age_tracker_ms: ageTrackerMs,
      wifi_state: wifiState,
      wifi_connected: wifiConnected,
      wifi_fresh: wifiFresh,
      wifi_last_update_ts: wifiLastTs,
      age_wifi_ms: ageWifiMs
    };
  }

  // Fresh tracker home (only reached if WiFi is stale or not present)
  if (trackerFresh && trackerState === "home") {
    return {
      trusted_state: "home",
      reason: "fresh_tracker_home",
      tracker_state: trackerState,
      tracker_fresh: trackerFresh,
      tracker_last_update_ts: trackerLastTs,
      age_tracker_ms: ageTrackerMs,
      wifi_state: wifiState,
      wifi_connected: wifiConnected,
      wifi_fresh: wifiFresh,
      wifi_last_update_ts: wifiLastTs,
      age_wifi_ms: ageWifiMs
    };
  }

  // Fresh tracker away
  if (trackerFresh && ["not_home", "away"].includes(trackerState)) {
    return {
      trusted_state: "away",
      reason: "fresh_tracker_away",
      tracker_state: trackerState,
      tracker_fresh: trackerFresh,
      tracker_last_update_ts: trackerLastTs,
      age_tracker_ms: ageTrackerMs,
      wifi_state: wifiState,
      wifi_connected: wifiConnected,
      wifi_fresh: wifiFresh,
      wifi_last_update_ts: wifiLastTs,
      age_wifi_ms: ageWifiMs
    };
  }

  // Otherwise degraded / ambiguous
  return {
    trusted_state: "unknown",
    reason: "stale_or_inconclusive",
    tracker_state: trackerState,
    tracker_fresh: trackerFresh,
    tracker_last_update_ts: trackerLastTs,
    age_tracker_ms: ageTrackerMs,
    wifi_state: wifiState,
    wifi_connected: wifiConnected,
    wifi_fresh: wifiFresh,
    wifi_last_update_ts: wifiLastTs,
    age_wifi_ms: ageWifiMs
  };
}

const people_detail = {
  phillip: trustPerson(p.people.phillip),
  kristine: trustPerson(p.people.kristine),
  kennedy: trustPerson(p.people.kennedy)
};

const trusted_people_home = Object.keys(people_detail).filter(
  name => people_detail[name].trusted_state === "home"
);

const trusted_people_away = Object.keys(people_detail).filter(
  name => people_detail[name].trusted_state === "away"
);

const trusted_people_unknown = Object.keys(people_detail).filter(
  name => people_detail[name].trusted_state === "unknown"
);

msg.person_trust_result = {
  trusted_people_home,
  trusted_people_away,
  trusted_people_unknown,
  people_detail,
  evaluated_ts: now
};

flow.set("person_trust_result", msg.person_trust_result);
return msg;

const trust = flow.get("person_trust_result");
const p = flow.get("presence_state");

if (!p) {
  return null;
}

const now = Date.now();
const MOTION_RECENT_MS = 10 * 60 * 1000;
const PRESENCE_HOLD_MS = 10 * 60 * 1000;   // hold last credible occupancy up to 10 min
const HEARTBEAT_STALE_MS = 15 * 60 * 1000; // if heartbeat dies, degrade to Unknown

const last = flow.get("last_presence_result") || null;

function recentMotionRooms() {
  return Object.keys(p.motion || {}).filter(room => {
    const active = p.motion?.[room] === true;
    const ts = Number(p.motion_ts?.[room] || 0);
    return active || ((now - ts) <= MOTION_RECENT_MS);
  });
}

const motionRooms = recentMotionRooms();
const motion = motionRooms.length > 0;

const heartbeatAgeMs = p.last_heartbeat_ts ? (now - p.last_heartbeat_ts) : null;
const heartbeatStale = heartbeatAgeMs !== null && heartbeatAgeMs > HEARTBEAT_STALE_MS;

// If trust is missing, preserve last known credible result rather than collapsing immediately
if (!trust) {
  if (last) {
    msg.presence_result = {
      ...last,
      reason: {
        ...(last.reason || {}),
        degraded: true,
        degraded_reason: "missing_person_trust_result",
        mode: String(p.jarvis_mode || "unknown"),
        motion,
        motion_rooms: motionRooms
      },
      health: {
        heartbeat_age_ms: heartbeatAgeMs,
        degraded: true
      },
      evaluated_ts: now
    };
    flow.set("presence_result", msg.presence_result);
    return msg;
  }
  return null;
}

const trustedHome = Array.isArray(trust.trusted_people_home) ? trust.trusted_people_home.length : 0;
const trustedAway = Array.isArray(trust.trusted_people_away) ? trust.trusted_people_away.length : 0;
const trustedUnknown = Array.isArray(trust.trusted_people_unknown) ? trust.trusted_people_unknown.length : 0;
const mode = String(p.jarvis_mode || "unknown");

let state = "Away";
let confidence = 0;

// Primary state decision
if (heartbeatStale) {
  state = "Unknown";
}
else if (mode === "vacation") {
  state = "Vacation";
}
else if ((mode === "night" || mode === "sleeping") && trustedHome > 0) {
  state = "Sleeping";
}
else if (trustedHome > 0) {
  state = "Occupied";
}
else if (motion && trustedUnknown > 0) {
  state = "Probable Occupancy";
}
else if (trustedUnknown > 0 && !motion) {
  state = "Unknown";
}
else if (motion && trustedHome === 0 && trustedUnknown === 0) {
  state = "Probable Occupancy";
}
else {
  state = "Away";
}

// Confidence model
confidence += trustedHome * 40;
confidence -= trustedUnknown * 15;

if (motion && trustedHome === 0) {
  confidence += 10;
}

if (trustedHome >= 2) {
  confidence += 10;
}

if (heartbeatStale) {
  confidence = Math.min(confidence, 20);
}

if (confidence < 0) confidence = 0;
if (confidence > 100) confidence = 100;

// Hold logic: do not collapse from strong occupied state to 0/unknown instantly unless evidence supports it
const lastWasCredibleOccupied =
  last &&
  ["Occupied", "Sleeping", "Probable Occupancy"].includes(String(last.state || "")) &&
  Number(last.confidence || 0) >= 40 &&
  (now - Number(last.evaluated_ts || 0)) <= PRESENCE_HOLD_MS;

const newStateLooksCollapsed =
  (state === "Away" || state === "Unknown") &&
  trustedHome === 0 &&
  !motion;

if (lastWasCredibleOccupied && newStateLooksCollapsed && !heartbeatStale) {
  state = last.state;
  confidence = Math.max(Number(last.confidence || 0), 50);

  msg.presence_result = {
    state,
    occupied: ["Occupied", "Probable Occupancy", "Sleeping"].includes(state),
    confidence,
    trusted_people_home: trust.trusted_people_home,
    trusted_people_away: trust.trusted_people_away,
    trusted_people_unknown: trust.trusted_people_unknown,
    active_people: trustedHome,
    active_rooms: motionRooms.join(", ") || "none",
    people_detail: trust.people_detail,
    reason: {
      mode,
      motion,
      motion_rooms: motionRooms,
      trusted_home: trust.trusted_people_home,
      trusted_away: trust.trusted_people_away,
      trusted_unknown: trust.trusted_people_unknown,
      held_previous_state: true,
      held_from_state: last.state
    },
    health: {
      heartbeat_age_ms: heartbeatAgeMs,
      degraded: false
    },
    evaluated_ts: now
  };

  flow.set("presence_result", msg.presence_result);
  flow.set("last_presence_result", msg.presence_result);
  return msg;
}

const occupied = ["Occupied", "Probable Occupancy", "Sleeping"].includes(state);

msg.presence_result = {
  state,
  occupied,
  confidence,
  trusted_people_home: trust.trusted_people_home,
  trusted_people_away: trust.trusted_people_away,
  trusted_people_unknown: trust.trusted_people_unknown,
  active_people: trustedHome,
  active_rooms: motionRooms.join(", ") || "none",
  people_detail: trust.people_detail,
  reason: {
    mode,
    motion,
    motion_rooms: motionRooms,
    trusted_home: trust.trusted_people_home,
    trusted_away: trust.trusted_people_away,
    trusted_unknown: trust.trusted_people_unknown,
    held_previous_state: false
  },
  health: {
    heartbeat_age_ms: heartbeatAgeMs,
    degraded: heartbeatStale
  },
  evaluated_ts: now
};

flow.set("presence_result", msg.presence_result);
flow.set("last_presence_result", msg.presence_result);
return msg;

const p = msg.presence_result;

if (!p) return null;

return [
  {
    topic: "jarvis/presence/state",
    payload: p.state
  },
  {
    topic: "jarvis/presence/confidence",
    payload: p.confidence
  },
  {
