  }
];

const p = msg.presence_result;
if (!p) return null;

msg.payload = Number(Number(p.confidence || 0).toFixed(1));
return msg;

const p = msg.presence_result;
if (!p) return null;

msg.payload = String(p.state || "Unknown");
return msg;

const topic = String(msg.topic || "");
const payload = msg.payload;

if (topic === "jarvis/presence/state") {
  msg.intent_update = {
    kind: "presence_state",
    value: String(payload || "")
  };
  return msg;
}

if (topic === "jarvis/posture/state") {
  msg.intent_update = {
    kind: "posture_state",
