  };
  return msg;
}

if (topic === "jarvis/presence/people_detail") {
  try {
    msg.intent_update = {
      kind: "people_detail",
      value: typeof payload === "string" ? JSON.parse(payload) : payload
    };
    return msg;
  } catch (e) {
    return null;
  }
}

if (topic === "jarvis_mode") {
  msg.intent_update = {
    kind: "jarvis_mode",
    value: String(payload || "").toLowerCase()
  };
  return msg;
}

if (["front_door", "patio_door", "overhead_door", "garage_door"].includes(topic)) {
  msg.intent_update = {
    kind: "door",
    name: topic,
    value: String(payload || "").toLowerCase()
  };
  return msg;
}

if (["living_room_motion", "stairwell_motion"].includes(topic)) {
  msg.intent_update = {
    kind: "motion",
    name: topic,
    value: String(payload || "").toLowerCase()
  };
  return msg;
}

if (topic === "tick") {
  msg.intent_update = { kind: "tick" };
  return msg;
}

return null;

let s = flow.get("intentLayerState");

if (!s || typeof s !== "object" || Array.isArray(s)) {
  s = {
    presence_state: "Unknown",
    posture_state: "Home",
    jarvis_mode: "day",
    people_detail: {},
    trusted_home_count: 0,

    front_door: "off",
    patio_door: "off",
    overhead_door: "off",
    garage_door: "off",

    living_room_motion: "off",
    stairwell_motion: "off",

    last_front_door_open_ts: 0,
    last_patio_door_open_ts: 0,
    last_overhead_door_open_ts: 0,
    last_garage_door_open_ts: 0,
    last_motion_ts: 0,

    last_intent: "idle",
    candidate_intent: "idle",
    candidate_since: 0,
    updated_ts: 0
  };
}

const u = msg.intent_update || {};
const now = Date.now();

function isOpen(v) {
  return ["on", "open", "opening", "true"].includes(String(v || "").toLowerCase());
}

function isMotion(v) {
  return ["on", "true", "detected"].includes(String(v || "").toLowerCase());
}

if (u.kind === "presence_state") {
  s.presence_state = String(u.value || "Unknown");
}

if (u.kind === "posture_state") {
  s.posture_state = String(u.value || "Home");
}

if (u.kind === "jarvis_mode") {
  s.jarvis_mode = String(u.value || "day");
}

if (u.kind === "people_detail") {
  const pd = u.value && typeof u.value === "object" ? u.value : {};
  s.people_detail = pd;
  s.trusted_home_count = Object.values(pd).filter(v => v?.trusted_state === "home").length;
}

if (u.kind === "door") {
  s[u.name] = u.value;

  if (u.name === "front_door" && isOpen(u.value)) s.last_front_door_open_ts = now;
  if (u.name === "patio_door" && isOpen(u.value)) s.last_patio_door_open_ts = now;
  if (u.name === "overhead_door" && isOpen(u.value)) s.last_overhead_door_open_ts = now;
  if (u.name === "garage_door" && isOpen(u.value)) s.last_garage_door_open_ts = now;
}

if (u.kind === "motion") {
  s[u.name] = u.value;
  if (isMotion(u.value)) s.last_motion_ts = now;
}

s.updated_ts = now;

flow.set("intentLayerState", s);
msg.intentLayerState = s;
return msg;

let s = flow.get("intentLayerState");
if (!s) return null;

const now = Date.now();
const INTENT_STABILITY_MS = 10 * 1000;
const DOOR_WINDOW_MS = 3 * 60 * 1000;
const MOTION_WINDOW_MS = 5 * 60 * 1000;

const trustedHome = Number(s.trusted_home_count || 0);
const posture = String(s.posture_state || "Home");
const mode = String(s.jarvis_mode || "day");
const presence = String(s.presence_state || "Unknown");

const recentFrontDoor = (now - Number(s.last_front_door_open_ts || 0)) <= DOOR_WINDOW_MS;
const recentPatioDoor = (now - Number(s.last_patio_door_open_ts || 0)) <= DOOR_WINDOW_MS;
const recentOverhead = (now - Number(s.last_overhead_door_open_ts || 0)) <= DOOR_WINDOW_MS;
const recentGarageDoor = (now - Number(s.last_garage_door_open_ts || 0)) <= DOOR_WINDOW_MS;
const recentMotion = (now - Number(s.last_motion_ts || 0)) <= MOTION_WINDOW_MS;

let candidate = "idle";
let reason = "default";

if ((recentFrontDoor || recentOverhead) && trustedHome > 0 && ["Home", "Caution"].includes(posture) && recentMotion) {
  candidate = "arriving_home";
  reason = "door_open_plus_trusted_presence_plus_motion";
}
else if ((recentFrontDoor || recentOverhead) && trustedHome === 0 && ["Away", "Alert", "Vacation"].includes(posture)) {
  candidate = "departing_home";
  reason = "door_open_while_house_non_home";
}
else if ((mode === "night" || posture === "Night") && recentMotion) {
  candidate = "bedtime_transition";
  reason = "night_mode_or_posture_with_recent_motion";
}
else if ((recentFrontDoor || recentOverhead) && trustedHome > 0 && posture === "Home") {
  candidate = "settling_in";
  reason = "recent_entry_with_trusted_home";
}
else if (recentOverhead || recentGarageDoor) {
  candidate = "garage_activity";
  reason = "garage_entry_activity";
}
else if (recentPatioDoor && trustedHome > 0 && posture !== "Night" && posture !== "Alert") {
  candidate = "patio_activity";
  reason = "patio_use_while_home";
}
else if (recentMotion && trustedHome > 0 && posture === "Home") {
  candidate = "normal_activity";
  reason = "trusted_home_with_recent_motion";
}
else {
  candidate = "idle";
  reason = "no_active_behavior_detected";
}

if (s.candidate_intent !== candidate) {
  s.candidate_intent = candidate;
  s.candidate_since = now;
}

let committedIntent = s.last_intent || candidate;

if ((now - Number(s.candidate_since || 0)) >= INTENT_STABILITY_MS || !s.last_intent) {
  committedIntent = s.candidate_intent;
}

const changed = committedIntent !== s.last_intent;
s.last_intent = committedIntent;

flow.set("intentLayerState", s);

msg.payload = committedIntent;
msg.intent_changed = changed;
msg.intent = {
  state: committedIntent,
  candidate_state: candidate,
  candidate_age_ms: now - Number(s.candidate_since || now),
  reason,
  trusted_home_count: trustedHome,
  posture_state: posture,
  presence_state: presence,
  jarvis_mode: mode,
  recent_front_door: recentFrontDoor,
  recent_patio_door: recentPatioDoor,
  recent_overhead: recentOverhead,
  recent_garage_door: recentGarageDoor,
  recent_motion: recentMotion,
  evaluated_ts: new Date().toISOString()
};

node.status({
  fill: committedIntent === "idle" ? "grey" : "green",
  shape: "dot",
  text: `${committedIntent} | candidate: ${candidate}`
});

return msg;

return [
  { topic: "jarvis/intent/state", payload: msg.intent.state },
  { topic: "jarvis/intent/reason", payload: msg.intent.reason }
];
